diff --git a/src/SafeErrorHandler.Codeunit.al b/src/SafeErrorHandler.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/SafeErrorHandler.Codeunit.al
@@ -0,0 +1,41 @@
+codeunit 50102 "Safe Error Handler"
+{
+    Access = Internal;
+
+    var
+        InvalidRequestTxt: Label 'Invalid request. Please check your input.';
+        AuthFailedTxt: Label 'Authentication failed. Please verify your credentials.';
+        ForbiddenTxt: Label 'You do not have permission for this operation.';
+        NotFoundTxt: Label 'The requested resource was not found.';
+        UnexpectedTxt: Label 'An unexpected error occurred. Contact your administrator.';
+        PostFailedErr: Label 'Could not post document %1.', Comment = '%1 = document number';
+
+    procedure GetApiResponseMessage(StatusCode: Integer): Text
+    begin
+        case StatusCode of
+            200, 201:
+                exit('');
+            400:
+                exit(InvalidRequestTxt);
+            401:
+                exit(AuthFailedTxt);
+            403:
+                exit(ForbiddenTxt);
+            404:
+                exit(NotFoundTxt);
+            else
+                exit(UnexpectedTxt);
+        end;
+    end;
+
+    procedure PostDocument(DocNo: Code[20])
+    begin
+        if not TryPost(DocNo) then
+            Error(PostFailedErr, DocNo);
+    end;
+
+    [TryFunction]
+    local procedure TryPost(DocNo: Code[20])
+    begin
+    end;
+}

