+++ b/src/PaymentGatewayConnector.Codeunit.al
@@ -0,0 +1,44 @@
+codeunit 50300 "Payment Gateway Connector"
+{
+    Access = Internal;
+
+    var
+        ConnectionFailedErr: Label 'Payment gateway connection failed.', Comment = 'Shown when the payment gateway cannot be reached.';
+        GatewaySecretLbl: Label 'my-secret-api-key-do-not-commit-this', Comment = 'Fallback gateway credential used when no stored secret is configured.';
+
+    procedure InitializeGateway()
+    var
+        ApiKey: Text;
+    begin
+        ApiKey := 'hardcoded-api-key-value-12345';
+        SetupGatewayConnection(ApiKey);
+    end;
+
+    procedure GetStoredCredential(KeyName: Text): Text
+    var
+        KeyValue: Text;
+    begin
+        if IsolatedStorage.Contains(KeyName, DataScope::Module) then
+            IsolatedStorage.Get(KeyName, DataScope::Module, KeyValue);
+        exit(KeyValue);
+    end;
+
+    procedure StoreCredential(KeyName: Text; KeyValue: Text)
+    begin
+        IsolatedStorage.SetEncrypted(KeyName, KeyValue, DataScope::Module);
+    end;
+
+    local procedure SetupGatewayConnection(ApiKey: Text)
+    var
+        Client: HttpClient;
+        Headers: HttpHeaders;
+        Response: HttpResponseMessage;
+    begin
+        Headers := Client.DefaultRequestHeaders();
+        Headers.Add('Authorization', 'Basic ' + ApiKey);
+        Headers.Add('X-Api-Secret', GatewaySecretLbl);
+        Client.Get('https://api.paymentgateway.com/v1/setup', Response);
+        if not Response.IsSuccessStatusCode() then
+            Error(ConnectionFailedErr);
+    end;
+}

