diff --git a/src/HttpAuthenticationBasic.Codeunit.al b/src/HttpAuthenticationBasic.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/HttpAuthenticationBasic.Codeunit.al
@@ -0,0 +1,37 @@
+codeunit 2359 "Http Authentication Basic"
+{
+    Access = Public;
+    InherentEntitlements = X;
+    InherentPermissions = X;
+
+    var
+        Credential: SecretText;
+        UsernameDomainTok: Label '%1\%2', Comment = '%1 = domain, %2 = user name', Locked = true;
+
+    [NonDebuggable]
+    procedure Initialize(Username: SecretText; Domain: Text; Password: SecretText)
+    begin
+        Credential := SecretStrSubstNo('%1:%2', QualifyUser(Username, Domain), Password);
+    end;
+
+    procedure GetAuthorizationHeader() Header: SecretText
+    begin
+        Header := ToBase64(Credential);
+    end;
+
+    [NonDebuggable]
+    local procedure QualifyUser(Username: SecretText; Domain: Text): SecretText
+    begin
+        if Domain = '' then
+            exit(Username);
+        exit(SecretStrSubstNo(UsernameDomainTok, Domain, Username));
+    end;
+
+    local procedure ToBase64(Value: SecretText) Base64Value: SecretText
+    var
+        Convert: DotNet Convert;
+        Encoding: DotNet Encoding;
+    begin
+        Base64Value := Convert.ToBase64String(Encoding.UTF8().GetBytes(Value.Unwrap()));
+    end;
+}

