+++ b/src/FADepreciationBook.Table.al
@@ -0,0 +1,75 @@
+table 50200 "FA Depreciation Book FP"
+{
+    DataClassification = CustomerContent;
+
+    fields
+    {
+        field(1; "FA No."; Code[20])
+        {
+            Caption = 'FA No.';
+            TableRelation = "Fixed Asset";
+        }
+
+        field(2; "Depreciation Book Code"; Code[10])
+        {
+            Caption = 'Depreciation Book Code';
+            TableRelation = "Depreciation Book";
+        }
+
+        field(3; Depreciation; Decimal)
+        {
+            FieldClass = FlowField;
+            CalcFormula = sum("FA Ledger Entry".Amount where("FA No." = field("FA No."),
+                                                            "Depreciation Book Code" = field("Depreciation Book Code"),
+                                                            "FA Posting Category" = const(Depreciation)));
+            Caption = 'Depreciation';
+        }
+
+        field(4; "Bonus Depr. Applied Amount"; Decimal)
+        {
+            FieldClass = FlowField;
+            CalcFormula = sum("FA Ledger Entry".Amount where("FA No." = field("FA No."),
+                                                            "Depreciation Book Code" = field("Depreciation Book Code"),
+                                                            "FA Posting Type" = const("Bonus Depreciation")));
+            Caption = 'Bonus Depr. Applied Amount';
+        }
+
+        field(5; "Use Half-Year Convention"; Boolean)
+        {
+            Caption = 'Use Half-Year Convention';
+
+            trigger OnValidate()
+            begin
+                // CORRECT: CalcFields in OnValidate runs once per user edit, not in a loop
+                // This is appropriate for validation logic that needs current flowfield values
+                CalcFields(Depreciation);
+                if Depreciation <> 0 then
+                    Error('Cannot change half-year convention after depreciation has been posted.');
+
+                CalcFields("Bonus Depr. Applied Amount");
+                if "Bonus Depr. Applied Amount" <> 0 then
+                    Error('Cannot change half-year convention when bonus depreciation has been applied.');
+            end;
+        }
+
+        field(6; "Depreciation Method"; Option)
+        {
+            OptionCaption = 'Straight-Line,Declining-Balance 1,Declining-Balance 2';
+            OptionMembers = "Straight-Line","Declining-Balance 1","Declining-Balance 2";
+            Caption = 'Depreciation Method';
+        }
+
+        field(7; "Starting Date"; Date)
+        {
+            Caption = 'Depreciation Starting Date';
+        }
+    }
+
+    keys
+    {
+        key(PK; "FA No.", "Depreciation Book Code")
+        {
+            Clustered = true;
+        }
+    }
+}
diff --git a/src/SalesOrderCard.Page.al b/src/SalesOrderCard.Page.al
