--- /dev/null
+++ b/src/SalesOrderCard.Page.al
@@ -0,0 +1,85 @@
+page 50201 "Sales Order Card FP"
+{
+    PageType = Card;
+    SourceTable = "Sales Header";
+    Caption = 'Sales Order Card FP';
+
+    layout
+    {
+        area(Content)
+        {
+            group(General)
+            {
+                Caption = 'General';
+
+                field("No."; Rec."No.")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the number of the sales order.';
+                }
+
+                field("Sell-to Customer No."; Rec."Sell-to Customer No.")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the number of the customer who will receive the products on the sales order.';
+                }
+
+                field("Document Date"; Rec."Document Date")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the date when the sales order was created.';
+                }
+
+                field("Total Amount"; TotalAmount)
+                {
+                    Caption = 'Total Amount Including VAT';
+                    ApplicationArea = All;
+                    Editable = false;
+                    ToolTip = 'Specifies the total amount including VAT for the sales order.';
+                }
+            }
+        }
+    }
+
+    actions
+    {
+        area(Processing)
+        {
+            action(RefreshTotals)
+            {
+                Caption = 'Refresh Totals';
+                ApplicationArea = All;
+                ToolTip = 'Recalculates and refreshes the total amount for the sales order.';
+                Image = Refresh;
+
+                trigger OnAction()
+                begin
+                    // CORRECT: Manual refresh action - user-initiated, runs once
+                    Rec.CalcFields("Amount Including VAT");
+                    TotalAmount := Rec."Amount Including VAT";
+                    Message('Total refreshed: %1', TotalAmount);
+                end;
+            }
+        }
+    }
+
+    var
+        TotalAmount: Decimal;
+
+    // CORRECT: OnAfterGetCurrRecord fires once per record selection, not per row
+    // This is the appropriate place to calculate values when user navigates to a record
+    trigger OnAfterGetCurrRecord()
+    begin
+        // Calculate total amount when user selects a sales order
+        // This runs once when the record is loaded/selected, not in a loop
+        Rec.CalcFields("Amount Including VAT");
+        TotalAmount := Rec."Amount Including VAT";
+    end;
+
+    trigger OnNewRecord(BelowxRec: Boolean)
+    begin
+        // CORRECT: Initialize values for new record - runs once per new record creation
+        TotalAmount := 0;
+        Rec."Document Date" := WorkDate();
+    end;
+}

