+{
+    procedure GetSetupValues()
+    var
+        GLSetup: Record "General Ledger Setup";
+        SalesSetup: Record "Sales & Receivables Setup";
+        InventorySetup: Record "Inventory Setup";
+        PurchSetup: Record "Purchases & Payables Setup";
+    begin
+        // CORRECT: Setup tables typically have only 1 record per company
+        // Any access pattern (Get, FindSet, FindFirst) is fine for singleton tables
+        GLSetup.Get();
+        SalesSetup.Get();
+        InventorySetup.Get();
+        PurchSetup.Get();
+
+        if GLSetup."Additional Reporting Currency" <> '' then
+            ProcessACYSettings(GLSetup);
+
+        if SalesSetup."Credit Warnings" <> SalesSetup."Credit Warnings"::"No Warning" then
+            EnableCreditWarnings(SalesSetup);
