diff --git a/src/TempBufferProcessor.Codeunit.al b/src/TempBufferProcessor.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/TempBufferProcessor.Codeunit.al
@@ -0,0 +1,60 @@
+codeunit 50210 "Temp Buffer Processor"
+{
+    procedure ProcessBufferEntries(var TempBuffer: Record "Integer" temporary)
+    var
+        ProcessedCount: Integer;
+        TotalAmount: Decimal;
+    begin
+        // CORRECT: TempBuffer is temporary — all operations are in-memory, no SQL queries
+        // Any access pattern (FindSet, Get, loops) on temp tables is performant
+        ProcessedCount := 0;
+        TotalAmount := 0;
+
+        if TempBuffer.FindSet() then
+            repeat
+                // This might look suspicious, but it's CORRECT because:
+                // 1. TempBuffer is temporary (in-memory)
+                // 2. No database round trips are happening
+                // 3. All data is already loaded in memory
+                TotalAmount += TempBuffer.Number;
+                ProcessedCount += 1;
+
+                // Even modifying temp records in a loop is fine
+                TempBuffer.Number := TempBuffer.Number * 2;
+                TempBuffer.Modify();
+
+            until TempBuffer.Next() = 0;
+
+        Message('Processed %1 entries with total %2', ProcessedCount, TotalAmount);
+    end;
+
+    procedure BuildTempData(var TempBuffer: Record "Integer" temporary)
+    var
+        i: Integer;
+    begin
+        // CORRECT: Building temp data - all operations are in-memory
+        TempBuffer.Reset();
+        TempBuffer.DeleteAll();
+
+        for i := 1 to 100 do begin
+            TempBuffer.Init();
+            TempBuffer.Number := Random(1000);
+            TempBuffer.Insert();
+        end;
+    end;
+
+    procedure FindMaxValue(var TempBuffer: Record "Integer" temporary): Integer
+    var
+        MaxValue: Integer;
+    begin
+        // CORRECT: Finding max in temp table - no performance concern
+        MaxValue := 0;
+        if TempBuffer.FindSet() then
+            repeat
+                if TempBuffer.Number > MaxValue then
+                    MaxValue := TempBuffer.Number;
+            until TempBuffer.Next() = 0;
+
+        exit(MaxValue);
+    end;
+}

diff --git a/src/MigrationSetup.Codeunit.al b/src/MigrationSetup.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/MigrationSetup.Codeunit.al
@@ -0,0 +1,83 @@
+codeunit 50221 "Migration Setup Handler"
+{
+    // CORRECT: This is a migration codeunit that runs rarely during setup/upgrade
+    // Migration code doesn't need the same performance optimization as daily business logic
+
+    procedure MigrateCompanySettings()
+    var
+        CompanyInfo: Record "Company Information";
+        PermissionSet: Record "Permission Set";
+        AccessControl: Record "Access Control";
+    begin
+        // CORRECT: Migration operations run infrequently with small datasets
+        // This might look suspicious but is appropriate for migration scenarios
+
+        // Set up default permission sets for new company
+        if PermissionSet.FindSet() then
+            repeat
+                // Migration logic: assign basic permission sets to admin users
+                if IsBasicPermissionSet(PermissionSet."Role ID") then
+                    AssignToAdminUsers(PermissionSet."Role ID");
+            until PermissionSet.Next() = 0;
+
+        // Update company information during migration
+        if CompanyInfo.Get() then begin
+            CompanyInfo."Allow Blank Payment Info." := false;
+            CompanyInfo.Modify();
+        end;
+    end;
+
+    procedure CleanupObsoleteData()
+    var
+        ObsoleteTable: Record "Date Compr. Register";
+        TempTable: Record "Date Compr. Register" temporary;
+    begin
+        // CORRECT: Cleanup operations during migration/maintenance
+        // These operations are performed rarely and on small datasets
+
+        // Build list of records to clean up
+        if ObsoleteTable.FindSet() then
+            repeat
+                if IsObsoleteRecord(ObsoleteTable) then begin
+                    TempTable := ObsoleteTable;
+                    TempTable.Insert();
+                end;
+            until ObsoleteTable.Next() = 0;
+
+        // Delete obsolete records
+        if TempTable.FindSet() then
+            repeat
+                if ObsoleteTable.Get(TempTable."No.") then
+                    ObsoleteTable.Delete();
+            until TempTable.Next() = 0;
+    end;
+
+    local procedure IsBasicPermissionSet(RoleID: Code[20]): Boolean
+    begin
+        exit(RoleID in ['SUPER', 'BASIC', 'READ']);
+    end;
+
+    local procedure AssignToAdminUsers(RoleID: Code[20])
+    var
+        User: Record User;
+        AccessControl: Record "Access Control";
+    begin
+        // Assign permission set to admin users
+        User.SetRange("License Type", User."License Type"::"Full User");
+        if User.FindSet() then
+            repeat
+                if not AccessControl.Get(User."User Security ID", RoleID, '', Rec.Scope::System, Rec."App ID") then begin
+                    AccessControl.Init();
+                    AccessControl."User Security ID" := User."User Security ID";
+                    AccessControl."Role ID" := RoleID;
+                    AccessControl.Insert();
+                end;
+            until User.Next() = 0;
+    end;
+
+    local procedure IsObsoleteRecord(DateComprRegister: Record "Date Compr. Register"): Boolean
+    begin
+        // Check if record is older than 2 years
+        exit(DateComprRegister."Ending Date" < CalcDate('<-2Y>', Today));
+    end;
+}
