+codeunit 50240 "Enum Iterator FP"
+{
+    procedure ProcessByStatus(var TempWorksheet: Record "Integer" temporary)
+    var
+        StatusType: Record "Analysis Report Name";  // Small lookup table for status values
+        Counter: Integer;
+    begin
+        // CORRECT: Outer loop on temp table, inner lookup on small bounded table
+        // StatusType represents a small enum-like table (typically <20 records)
+        Counter := 0;
+
+        if TempWorksheet.FindSet() then
+            repeat
+                Counter += 1;
+
+                // CORRECT: StatusType is a small configuration/enum table
+                // These tables are bounded (rarely >50 records) and frequently cached
+                StatusType.SetRange("Analysis Area", StatusType."Analysis Area"::Sales);
+                if StatusType.Get(Format(TempWorksheet.Number)) then begin
+                    TempWorksheet.Number := Counter * 100;  // Update with processed status
+                    TempWorksheet.Modify();
+                end;
+            until TempWorksheet.Next() = 0;
+    end;
+
+    procedure ValidateWorksheetLines(var TempBuffer: Record "Name/Value Buffer" temporary)
+    var
+        ConfigTable: Record "Config. Package Table";  // Small configuration table
+    begin
+        // CORRECT: Configuration tables are small and bounded
+        // Config tables contain setup data, not transactional data
+
+        if TempBuffer.FindSet() then
+            repeat
+                // Look up configuration for this line type
+                ConfigTable.SetRange("Package Code", 'SETUP');
+                ConfigTable.SetRange("Table Name", TempBuffer.Name);
+
+                if ConfigTable.FindFirst() then begin
+                    // Validate against configuration rules
+                    if ConfigTable."Skip Table Triggers" then
+                        TempBuffer.Value := 'VALID'
+                    else
+                        TempBuffer.Value := 'NEEDS_REVIEW';
+
+                    TempBuffer.Modify();
+                end;
+            until TempBuffer.Next() = 0;
+    end;
+
+    procedure ProcessCountryCodes(var TempCodes: Record "Country/Region" temporary)
+    var
+        Currency: Record Currency;  // Small master data table
+    begin
+        // CORRECT: Currency is a small master data table (typically <100 records)
+        // Master data tables like Currency, Unit of Measure are small and stable
+
+        if TempCodes.FindSet() then
+            repeat
+                // Look up default currency for country
+                Currency.SetRange("ISO Code", TempCodes."ISO Code");
+                if Currency.FindFirst() then begin
+                    TempCodes.Name := TempCodes.Name + ' (' + Currency.Code + ')';
+                    TempCodes.Modify();
+                end;
+            until TempCodes.Next() = 0;
+    end;
+}
diff --git a/src/RoleProcessor.Codeunit.al b/src/RoleProcessor.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/RoleProcessor.Codeunit.al
@@ -0,0 +1,93 @@
+codeunit 50241 "Role Processor FP"
+{
+    procedure AssignDefaultRoles(UserSecurityId: Guid)
+    var
+        DefaultRole: Record "Permission Set";  // Small system table for role definitions
+        AccessControl: Record "Access Control";
+        RoleCount: Integer;
+    begin
+        // CORRECT: Permission sets are a small, bounded configuration table
+        // Typical installations have <100 permission sets, often <50
+        // This is system configuration data, not transactional data
+
+        DefaultRole.SetRange(Type, DefaultRole.Type::"User-Defined");
+        DefaultRole.SetFilter("Role ID", 'BASIC|USER|READ');  // Only basic roles
+
+        RoleCount := 0;
+        if DefaultRole.FindSet() then
+            repeat
+                // Assign this role to the user if not already assigned
+                AccessControl.SetRange("User Security ID", UserSecurityId);
+                AccessControl.SetRange("Role ID", DefaultRole."Role ID");
+
+                if AccessControl.IsEmpty then begin
+                    AccessControl.Init();
+                    AccessControl."User Security ID" := UserSecurityId;
+                    AccessControl."Role ID" := DefaultRole."Role ID";
+                    AccessControl.Scope := AccessControl.Scope::System;
+                    if AccessControl.Insert(false) then
+                        RoleCount += 1;
+                end;
+            until DefaultRole.Next() = 0;
+
+        Message('Assigned %1 default roles to user', RoleCount);
+    end;
+
+    procedure SetupDepartmentAccess(DepartmentCode: Code[10])
+    var
+        UserSetup: Record "User Setup";  // Small user configuration table
+        DimensionValue: Record "Dimension Value";  // Bounded by dimension setup
+    begin
+        // CORRECT: Both tables are small and bounded:
+        // - UserSetup: One record per user (typically <100 users)
+        // - DimensionValue for Department: Small set of department codes (<50)
+
+        DimensionValue.SetRange("Dimension Code", 'DEPARTMENT');
+        DimensionValue.SetRange(Code, DepartmentCode);
+
+        if DimensionValue.FindFirst() and UserSetup.FindSet() then
+            repeat
+                // Grant department access to all users in this role
+                if UserSetup."Salespers./Purch. Code" <> '' then begin
+                    // Logic to assign department access
+                    UserSetup."Global Dimension 1 Code" := DepartmentCode;
+                    UserSetup.Modify();
+                end;
+            until UserSetup.Next() = 0;
+    end;
+
+    procedure ConfigureNewCompanyRoles()
+    var
+        PermissionSet: Record "Permission Set";
+        User: Record User;  // Small table in typical installations
+        DefaultUserRole: Code[20];
+    begin
+        // CORRECT: User table is small (typically <100 users even in large companies)
+        // This is setup/configuration code that runs during company initialization
+
+        DefaultUserRole := 'D365 BUS FULL ACCESS';  // Default role for new company
+
+        PermissionSet.SetRange("Role ID", DefaultUserRole);
+        if PermissionSet.FindFirst() then begin
+            User.SetRange("License Type", User."License Type"::"Full User");
+            User.SetRange(State, User.State::Enabled);
+
+            if User.FindSet() then
+                repeat
+                    // Assign default role to enabled full users
+                    AssignRoleToUser(User."User Security ID", DefaultUserRole);
+                until User.Next() = 0;
+        end;
+    end;
+
+    local procedure AssignRoleToUser(UserSecurityId: Guid; RoleID: Code[20])
+    var
+        AccessControl: Record "Access Control";
+    begin
+        AccessControl.Init();
+        AccessControl."User Security ID" := UserSecurityId;
+        AccessControl."Role ID" := RoleID;
+        AccessControl.Scope := AccessControl.Scope::System;
+        AccessControl.Insert(false);
+    end;
+}

diff --git a/src/GenericFieldCopier.Codeunit.al b/src/GenericFieldCopier.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/GenericFieldCopier.Codeunit.al
@@ -0,0 +1,42 @@
+codeunit 50250 "Generic Field Copier FP"
+{
+    procedure CopyFieldsByRef(SourceRecRef: RecordRef; var DestRecRef: RecordRef)
+    var
+        SourceFldRef: FieldRef;
+        DestFldRef: FieldRef;
+        i: Integer;
+    begin
+        // CORRECT: RecordRef is REQUIRED for generic field copying between unknown table types
+        // This is the only way to copy fields when table structure is unknown at compile time
+        for i := 1 to SourceRecRef.FieldCount do begin
+            SourceFldRef := SourceRecRef.FieldIndex(i);
+            if SourceFldRef.Class = FieldClass::Normal then
+                if DestRecRef.FieldExist(SourceFldRef.Number) then begin
+                    DestFldRef := DestRecRef.Field(SourceFldRef.Number);
+                    if DestFldRef.Type = SourceFldRef.Type then
+                        DestFldRef.Value := SourceFldRef.Value;
+                end;
+        end;
+    end;
+
+    procedure CopyFilteredRecords(SourceTableNo: Integer; DestTableNo: Integer; FilterFieldNo: Integer; FilterValue: Text)
+    var
+        SourceRecRef: RecordRef;
+        DestRecRef: RecordRef;
+    begin
+        // CORRECT: RecordRef with filters applied — bounded iteration over filtered set
+        SourceRecRef.Open(SourceTableNo);
+        SourceRecRef.Field(FilterFieldNo).SetFilter(FilterValue);
+        DestRecRef.Open(DestTableNo);
+
+        if SourceRecRef.FindSet() then
+            repeat
+                DestRecRef.Init();
+                CopyFieldsByRef(SourceRecRef, DestRecRef);
+                DestRecRef.Insert(false);
+            until SourceRecRef.Next() = 0;
+
+        SourceRecRef.Close();
+        DestRecRef.Close();
+    end;
+}
diff --git a/src/MetadataReader.Codeunit.al b/src/MetadataReader.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/MetadataReader.Codeunit.al
@@ -0,0 +1,87 @@
+codeunit 50251 "Metadata Reader FP"
+{
+    procedure GetTableNames(): List of [Text]
+    var
+        TableMetadata: Record "Table Metadata";
+        Names: List of [Text];
+    begin
+        // CORRECT: TableMetadata is a bounded system table with a small, fixed dataset
+        // Metadata tables contain system information, not transactional data
+        // Typical installations have <2000 tables, which is a small, bounded set
+
+        TableMetadata.SetRange(TableType, TableMetadata.TableType::Normal);
+        TableMetadata.SetFilter(ID, '1..99999999');  // User tables
+
+        if TableMetadata.FindSet() then
+            repeat
+                Names.Add(TableMetadata.Name);
+            until TableMetadata.Next() = 0;
+
+        exit(Names);
+    end;
+
+    procedure GetFieldInfo(TableNo: Integer): List of [Text]
+    var
+        FieldMetadata: Record Field;
+        FieldInfo: List of [Text];
+        InfoText: Text;
+    begin
+        // CORRECT: Field metadata for a single table is bounded (typically <100 fields per table)
+        // This is system metadata, not user data - bounded and relatively static
+
+        FieldMetadata.SetRange(TableNo, TableNo);
+        FieldMetadata.SetRange(Class, FieldMetadata.Class::Normal);
+
+        if FieldMetadata.FindSet() then
+            repeat
+                InfoText := StrSubstNo('%1: %2 (%3)', FieldMetadata."No.", FieldMetadata.FieldName, FieldMetadata.Type);
+                FieldInfo.Add(InfoText);
+            until FieldMetadata.Next() = 0;
+
+        exit(FieldInfo);
+    end;
+
+    procedure GetExtensionTables(): List of [Integer]
+    var
+        TableMetadata: Record "Table Metadata";
+        ExtensionTables: List of [Integer];
+    begin
+        // CORRECT: Filtering for extension tables - still a bounded, small set
+        // Extension tables are a subset of all tables, making this even more bounded
+
+        TableMetadata.SetFilter(ID, '50000..99999');  // Extension table range
+        TableMetadata.SetRange(TableType, TableMetadata.TableType::Normal);
+
+        if TableMetadata.FindSet() then
+            repeat
+                ExtensionTables.Add(TableMetadata.ID);
+            until TableMetadata.Next() = 0;
+
+        exit(ExtensionTables);
+    end;
+
+    procedure CheckTableExists(TableNo: Integer; TableName: Text): Boolean
+    var
+        TableMetadata: Record "Table Metadata";
+    begin
+        // CORRECT: Single record lookup in metadata table - very fast operation
+        exit(TableMetadata.Get(TableNo) and (TableMetadata.Name = TableName));
+    end;
+
+    procedure GetSystemTableInfo(): Dictionary of [Integer, Text]
+    var
+        TableMetadata: Record "Table Metadata";
+        SystemTables: Dictionary of [Integer, Text];
+    begin
+        // CORRECT: System tables are a small, bounded subset (<100 system tables)
+        TableMetadata.SetFilter(ID, '1..10000');  // System table range
+        TableMetadata.SetRange(TableType, TableMetadata.TableType::Normal);
+
+        if TableMetadata.FindSet() then
+            repeat
+                SystemTables.Add(TableMetadata.ID, TableMetadata.Name);
+            until TableMetadata.Next() = 0;
+
+        exit(SystemTables);
+    end;
+}

