+        TargetLocation."Post Code" := SourceLocation."Post Code";
+        TargetLocation."Country/Region Code" := SourceLocation."Country/Region Code";
+        TargetLocation."Phone No." := SourceLocation."Phone No.";
+        TargetLocation.Contact := SourceLocation.Contact;
+        TargetLocation.Insert(true);
+    end;
+
+    procedure CopyCustomer(SourceNo: Code[20]; TargetNo: Code[20])
+    var
+        SourceCustomer: Record Customer;
+        TargetCustomer: Record Customer;
+    begin
+        // CORRECT: SetLoadFields on Customer (800k rows, 100+ fields) — only loads needed subset
+        SourceCustomer.SetLoadFields(Name, "Name 2", Address, "Address 2", City, "Post Code",
+            "Country/Region Code", "Phone No.", "Customer Posting Group",
+            "Gen. Bus. Posting Group", "Payment Terms Code", "Payment Method Code");
+        if not SourceCustomer.Get(SourceNo) then
+            exit;
+
+        TargetCustomer.Init();
+        TargetCustomer."No." := TargetNo;
+        TargetCustomer.Name := SourceCustomer.Name;
+        TargetCustomer."Name 2" := SourceCustomer."Name 2";
+        TargetCustomer.Address := SourceCustomer.Address;
+        TargetCustomer."Address 2" := SourceCustomer."Address 2";
+        TargetCustomer.City := SourceCustomer.City;
+        TargetCustomer."Post Code" := SourceCustomer."Post Code";
+        TargetCustomer."Country/Region Code" := SourceCustomer."Country/Region Code";
+        TargetCustomer."Phone No." := SourceCustomer."Phone No.";
+        TargetCustomer."Customer Posting Group" := SourceCustomer."Customer Posting Group";
+        TargetCustomer."Gen. Bus. Posting Group" := SourceCustomer."Gen. Bus. Posting Group";
+        TargetCustomer."Payment Terms Code" := SourceCustomer."Payment Terms Code";
+        TargetCustomer."Payment Method Code" := SourceCustomer."Payment Method Code";
+        TargetCustomer.Insert(true);
+    end;
+
+    procedure BackupLocationData(LocationCode: Code[10]): Text
+    var
+        Location: Record Location;
+    begin
+        // CORRECT: SetLoadFields — only 5 of ~40 fields needed for backup
+        Location.SetLoadFields(Name, Address, City, "Country/Region Code");
+        if not Location.Get(LocationCode) then
