diff --git a/src/SetupValidator.Codeunit.al b/src/SetupValidator.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/SetupValidator.Codeunit.al
@@ -0,0 +1,102 @@
+codeunit 50260 "Setup Validator FP"
+{
+    procedure ValidateSetup()
+    var
+        FASetup: Record "FA Setup";
+        GLSetup: Record "General Ledger Setup";
+        SalesSetup: Record "Sales & Receivables Setup";
+        PurchSetup: Record "Purchases & Payables Setup";
+        InventorySetup: Record "Inventory Setup";
+    begin
+        // CORRECT: Setup tables are singletons (1 record per company)
+        // Get() on singleton tables is always appropriate and fast
+
+        FASetup.Get();
+        FASetup.TestField("Default Depr. Book");
+
+        GLSetup.Get();
+        GLSetup.TestField("LCY Code");
+        GLSetup.TestField("Posting Allowed From");
+        GLSetup.TestField("Posting Allowed To");
+
+        SalesSetup.Get();
+        SalesSetup.TestField("Customer Nos.");
+
+        PurchSetup.Get();
+        PurchSetup.TestField("Vendor Nos.");
+
+        InventorySetup.Get();
+        InventorySetup.TestField("Item Nos.");
+
+        // Validate cross-setup consistency
+        ValidateCurrencyConsistency(GLSetup, SalesSetup);
+    end;
+
+    procedure GetLocationName(LocationCode: Code[10]): Text
+    var
+        Location: Record Location;
+    begin
+        // CORRECT: SetLoadFields + Get is the Microsoft-recommended pattern
+        // This loads only the required fields, making it more efficient than full Get
+        Location.SetLoadFields(Name);
+        if Location.Get(LocationCode) then
+            exit(Location.Name);
+        exit('');
+    end;
+
+    procedure GetCustomerInfo(CustomerNo: Code[20]; var Name: Text; var CreditLimit: Decimal)
+    var
+        Customer: Record Customer;
+    begin
+        // CORRECT: SetLoadFields pattern for loading specific fields only
+        Customer.SetLoadFields(Name, "Credit Limit (LCY)");
+        if Customer.Get(CustomerNo) then begin
+            Name := Customer.Name;
+            CreditLimit := Customer."Credit Limit (LCY)";
+        end else begin
+            Name := '';
+            CreditLimit := 0;
+        end;
+    end;
+
+    procedure GetVendorPaymentTerms(VendorNo: Code[20]): Code[10]
+    var
+        Vendor: Record Vendor;
+    begin
+        // CORRECT: Loading only the specific field needed
+        Vendor.SetLoadFields("Payment Terms Code");
+        if Vendor.Get(VendorNo) then
+            exit(Vendor."Payment Terms Code");
+        exit('');
+    end;
+
+    local procedure ValidateCurrencyConsistency(GLSetup: Record "General Ledger Setup"; SalesSetup: Record "Sales & Receivables Setup")
+    var
+        Currency: Record Currency;
+    begin
+        // CORRECT: Single Get() call for validation
+        if GLSetup."Additional Reporting Currency" <> '' then begin
+            Currency.Get(GLSetup."Additional Reporting Currency");
+            Currency.TestField("Amount Rounding Precision");
+        end;
+    end;
+
+    procedure ValidateNumberSeries()
+    var
+        SalesSetup: Record "Sales & Receivables Setup";
+        NoSeries: Record "No. Series";
+    begin
+        // CORRECT: Setup validation with related record checks
+        SalesSetup.Get();
+
+        if SalesSetup."Customer Nos." <> '' then begin
+            NoSeries.Get(SalesSetup."Customer Nos.");
+            NoSeries.TestField("Default Nos.", true);
+        end;
+
+        if SalesSetup."Invoice Nos." <> '' then begin
+            NoSeries.Get(SalesSetup."Invoice Nos.");
+            NoSeries.TestField("Default Nos.", true);
+        end;
+    end;
+}

