+    APIVersion = 'v1.0';
+    EntityName = 'tempRecord';
+    EntitySetName = 'tempRecords';
+    SourceTable = "Name/Value Buffer";
+    SourceTableTemporary = true;  // CORRECT: This makes all operations in-memory
+    DelayedInsert = true;
+
+    layout
+    {
+        area(Content)
+        {
+            repeater(GroupName)
+            {
+                field(id; Rec.ID)
+                {
+                    Caption = 'ID';
+                }
+
+                field(name; Rec.Name)
+                {
+                    Caption = 'Name';
+                }
+
+                field(value; Rec.Value)
+                {
+                    Caption = 'Value';
+                }
+
+                field(valueLong; Rec."Value BLOB")
+                {
+                    Caption = 'Value Long';
+                }
+            }
+        }
+    }
+
+    // CORRECT: All triggers operate on temp data (in-memory)
+    // SourceTableTemporary = true ensures no database operations
+
+    trigger OnOpenPage()
+    var
+        Counter: Integer;
+    begin
+        // CORRECT: Initialize temp data for API
+        Rec.DeleteAll();
+
+        for Counter := 1 to 10 do begin
+            Rec.Init();
+            Rec.ID := Counter;
+            Rec.Name := 'Item ' + Format(Counter);
+            Rec.Value := Format(Counter * 100);
+            Rec.Insert();
+        end;
+    end;
+
+    trigger OnInsertRecord(BelowxRec: Boolean): Boolean
+    var
+        NextID: Integer;
+    begin
+        // CORRECT: Temp table operations for API insert
+        if Rec.FindLast() then
+            NextID := Rec.ID + 1
+        else
+            NextID := 1;
+
+        Rec.ID := NextID;
+        exit(true);
+    end;
+
+    trigger OnModifyRecord(): Boolean
+    begin
+        // CORRECT: Validation on temp record modification
+        if Rec.Name = '' then
+            Error('Name cannot be empty');
+
+        if Rec.Value = '' then
+            Rec.Value := 'DEFAULT';
+
+        exit(true);
+    end;
+
+    trigger OnDeleteRecord(): Boolean
+    begin
+        // CORRECT: Allow deletion in temp table API
+        exit(true);
+    end;
+}
diff --git a/src/TempTableCalculator.Codeunit.al b/src/TempTableCalculator.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/TempTableCalculator.Codeunit.al
@@ -0,0 +1,90 @@
+codeunit 50270 "Temp Table Calculator FP"
+{
+    procedure CalculateTotals(var TempLine: Record "Sales Line" temporary)
+    var
+        Total: Decimal;
+        LineCount: Integer;
+    begin
+        // CORRECT: All operations on temp table are in-memory and performant
+        // Temporary tables don't hit the database, so any access pattern is fine
+
+        TempLine.Reset();
+        Total := 0;
+        LineCount := 0;
+
+        if TempLine.FindSet() then
+            repeat
+                LineCount += 1;
+
+                // CORRECT: CalcFields on temp table is in-memory calculation
+                TempLine.CalcFields("Outstanding Amount");
+                Total += TempLine."Outstanding Amount";
+
+                // Update running total on each line
+                TempLine."Line Amount" := Total;
+                TempLine.Modify();
+
+            until TempLine.Next() = 0;
+
+        Message('Processed %1 lines with total %2', LineCount, Total);
+    end;
+
+    procedure ProcessTempData(var TempItem: Record Item temporary)
+    var
+        ProcessedCount: Integer;
+        MaxUnitPrice: Decimal;
+    begin
+        // CORRECT: Complex processing on temp table - all in-memory operations
+        ProcessedCount := 0;
+        MaxUnitPrice := 0;
+
+        // First pass: find maximum unit price
+        if TempItem.FindSet() then
+            repeat
+                if TempItem."Unit Price" > MaxUnitPrice then
+                    MaxUnitPrice := TempItem."Unit Price";
+            until TempItem.Next() = 0;
+
+        // Second pass: update items based on max price
+        TempItem.Reset();
+        if TempItem.FindSet(true) then
+            repeat
+                if TempItem."Unit Price" = MaxUnitPrice then
+                    TempItem.Description := TempItem.Description + ' (PREMIUM)';
+
+                ProcessedCount += 1;
+                TempItem.Modify();
+            until TempItem.Next() = 0;
+
+        Message('Updated %1 items, max price: %2', ProcessedCount, MaxUnitPrice);
+    end;
+
+    procedure BuildAnalysisData(var TempBuffer: Record "Analysis Report Chart Setup" temporary)
+    var
+        Counter: Integer;
+        i: Integer;
+    begin
+        // CORRECT: Building and manipulating temp data - all in-memory
+        TempBuffer.DeleteAll();
+        Counter := 0;
+
+        for i := 1 to 50 do begin
+            TempBuffer.Init();
+            TempBuffer."User ID" := UserId;
+            TempBuffer."Analysis Report Name" := 'TEMP_ANALYSIS_' + Format(i);
+            TempBuffer."Analysis Line Template Name" := 'DEFAULT';
+            TempBuffer."Analysis Column Template Name" := 'DEFAULT';
+            TempBuffer.Insert();
+            Counter += 1;
+        end;
+
+        // Process the temp data
+        if TempBuffer.FindSet() then
+            repeat
+                TempBuffer."Chart Type" := TempBuffer."Chart Type"::Column;
+                TempBuffer.Modify();
+            until TempBuffer.Next() = 0;
+
+        Message('Built %1 analysis entries', Counter);
+    end;
+}

