+                ProcessedCount += 1;
+
+                if ProcessedCount mod 50 = 0 then
+                    UpdateProgressDialog(ProcessedCount, TotalToProcess);
+
+            until ReservWorksheetLine.Next() = 0;
+        end;
+
+        Message('Successfully allocated %1 reservations.', ProcessedCount);
