+            Caption = 'Status';
+            OptionMembers = Idle,Running,Error;
+        }
+        field(5; "Last Error Message"; Text[250])
+        {
+            Caption = 'Last Error Message';
+        }
+        field(6; "Retry Count"; Integer)
+        {
+            Caption = 'Retry Count';
+        }
+        field(7; "Next Retry Time"; DateTime)
+        {
+            Caption = 'Next Retry Time';
+        }
+    }
+
+    keys
+    {
+        key(PK; "Primary Key") { Clustered = true; }
+    }
+
+    procedure GetOrCreate(): Record "EA Agent Status"
+    begin
+        Rec.LockTable();
+        if not Rec.Get() then begin
+            Rec.Init();
+            Rec."Primary Key" := '';
+            Rec."Notifications Enabled" := true;
+            Rec.Status := Rec.Status::Idle;
+            Rec."Last Run" := CurrentDateTime();
+            Rec.Insert();
+        end;
+        exit(Rec);
+    end;
+
+    procedure ShouldRunNotifications(): Boolean
+    begin
+        exit(GetOrCreate()."Notifications Enabled");
+    end;
+
+    procedure UpdateStatus(NewStatus: Option; ErrorMessage: Text[250])
+    var
+        AgentStatus: Record "EA Agent Status";
+    begin
+        AgentStatus := GetOrCreate();
+        AgentStatus.Status := NewStatus;
+        AgentStatus."Last Run" := CurrentDateTime();
+        AgentStatus."Last Error Message" := ErrorMessage;
+        if NewStatus = AgentStatus.Status::Error then
+            AgentStatus."Retry Count" += 1
+        else
+            AgentStatus."Retry Count" := 0;
+        AgentStatus.Modify();
+    end;
+
+    procedure IsRunning(): Boolean
+    var
+        AgentStatus: Record "EA Agent Status";
+    begin
+        AgentStatus := GetOrCreate();
+        exit(AgentStatus.Status = AgentStatus.Status::Running);
+    end;
+}
