+codeunit 50131 "Vend. Entry Edit Handler"
+{
+    Access = Public;
+
+    procedure UpdateRelatedAdvanceLetterEntries(EntryNo: Integer; Level: Integer)
+    var
+        VendLedgerEntry: Record "Vendor Ledger Entry";
+        RelatedEntry: Record "Vendor Ledger Entry";
+        MaxRecursionLevel: Integer;
+    begin
+        MaxRecursionLevel := 50;
+        if Level > MaxRecursionLevel then
+            Error('Maximum recursion level exceeded for entry %1', EntryNo);
+
+        VendLedgerEntry.SetLoadFields("Letter No.", "Letter Line No.", "Advance Letter Template Code", "Document No.", "Vendor No.");
