+codeunit 50140 "Purch. Rcpt. Line Mgmt."
+{
+    Access = Public;
+
+    procedure ProcessReceiptLines(OrderNo: Code[20])
+    var
+        PurchRcptLine: Record "Purch. Rcpt. Line";
+        ProcessedCount: Integer;
+    begin
+        // Validate order number
+        if OrderNo = '' then
+            exit;
+
+        // Setup filters for receipt lines
+        PurchRcptLine.SetRange("Order No.", OrderNo);
+        PurchRcptLine.SetRange(Type, PurchRcptLine.Type::Item);
+        PurchRcptLine.SetFilter(Quantity, '>0');
+
+        if PurchRcptLine.IsEmpty() then
+            exit;
+
+        if PurchRcptLine.FindSet() then
+            repeat
+                // Bad: CalcFields on FlowField inside a loop — N separate SQL queries
+                PurchRcptLine.CalcFields("Currency Code");
+
+                if PurchRcptLine."Currency Code" <> '' then begin
+                    ProcessForeignCurrencyLine(PurchRcptLine);
+                    ProcessedCount += 1;
+                end else begin
+                    ProcessLocalCurrencyLine(PurchRcptLine);
+                end;
+
+                // Update line status
+                UpdateLineProcessingStatus(PurchRcptLine);
+
+            until PurchRcptLine.Next() = 0;
+
+        // Log processing completion
+        LogProcessingComplete(OrderNo, ProcessedCount);
+    end;
+
+    local procedure ProcessForeignCurrencyLine(PurchRcptLine: Record "Purch. Rcpt. Line")
+    begin
+        // Process foreign currency line with exchange rate calculations
+    end;
+
+    local procedure ProcessLocalCurrencyLine(PurchRcptLine: Record "Purch. Rcpt. Line")
+    begin
+        // Process local currency line
+    end;
+
+    local procedure UpdateLineProcessingStatus(var PurchRcptLine: Record "Purch. Rcpt. Line")
+    begin
+        // Update processing flags
+        PurchRcptLine."Processed Date" := Today();
+        PurchRcptLine.Modify();
+    end;
+
+    local procedure LogProcessingComplete(OrderNo: Code[20]; ProcessedCount: Integer)
+    begin
+        // Log completion statistics
+    end;
+}
