+codeunit 50400 "Configuration Helper"
+{
+    Access = Public;
+
+    procedure GetOrCreateSetup(): Record "General Ledger Setup"
+    var
+        GLSetup: Record "General Ledger Setup";
+    begin
+        GLSetup.LockTable();
+        if not GLSetup.Get() then begin
+            GLSetup.Init();
+            GLSetup."Allow Posting From" := CalcDate('<-CM>', WorkDate());
+            GLSetup."Allow Posting To" := CalcDate('<CM>', WorkDate());
+            GLSetup.Insert(true);
+        end;
+        exit(GLSetup);
+    end;
+
+    procedure GetCustomerDisplayName(CustomerNo: Code[20]): Text[100]
+    var
+        Customer: Record Customer;
+    begin
+        Customer.LockTable();
+        Customer.SetLoadFields(Name);
+        Customer.SetRange("No.", CustomerNo);
+        Customer.SetRange(Blocked, Customer.Blocked::" ");
+        if Customer.FindFirst() then
+            exit(Customer.Name)
+        else
+            exit('');
+    end;
+
+    procedure GetItemDescription(ItemNo: Code[20]): Text[100]
+    var
+        Item: Record Item;
+    begin
+        Item.ReadIsolation := IsolationLevel::ReadCommitted;
+        Item.SetLoadFields(Description);
+        if Item.Get(ItemNo) then
+            exit(Item.Description)
+        else
+            exit('');
+    end;
+
+    procedure GetCurrencyExchangeRate(CurrencyCode: Code[10]; PostingDate: Date): Decimal
+    var
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+    begin
+        CurrencyExchangeRate.SetRange("Currency Code", CurrencyCode);
+        CurrencyExchangeRate.SetRange("Starting Date", 0D, PostingDate);
+        if CurrencyExchangeRate.FindLast() then
+            exit(CurrencyExchangeRate."Exchange Rate Amount")
+        else
+            exit(1);
+    end;
+
+    procedure GetDefaultDimension(TableID: Integer; No: Code[20]): Code[20]
+    var
+        DefaultDimension: Record "Default Dimension";
+    begin
+        DefaultDimension.SetRange("Table ID", TableID);
+        DefaultDimension.SetRange("No.", No);
+        DefaultDimension.SetRange("Dimension Code", 'DEPARTMENT');
+        if DefaultDimension.FindFirst() then
+            exit(DefaultDimension."Dimension Value Code")
+        else
+            exit('');
+    end;
+
+    procedure IsFeatureEnabled(FeatureKey: Text[50]): Boolean
+    var
+        FeatureDataUpdateStatus: Record "Feature Data Update Status";
+    begin
+        FeatureDataUpdateStatus.ReadIsolation := IsolationLevel::ReadCommitted;
+        FeatureDataUpdateStatus.SetRange("Feature Key", FeatureKey);
+        if FeatureDataUpdateStatus.FindFirst() then
+            exit(FeatureDataUpdateStatus."Feature Status" = FeatureDataUpdateStatus."Feature Status"::Enabled)
+        else
+            exit(false);
