+    procedure ValidateAssemblyLineQuantity(var AssemblyLine: Record "Assembly Line")
+    begin
+        if AssemblyLine.Quantity <= 0 then
+            Error('Quantity must be greater than zero');
+
+        if AssemblyLine.Type = AssemblyLine.Type::Item then
+            if not CheckAvailability(AssemblyLine) then
+                Message('Insufficient inventory available for item %1', AssemblyLine."No.");
+    end;
+}
diff --git a/src/PurchAllocAccMgt.Codeunit.al b/src/PurchAllocAccMgt.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/PurchAllocAccMgt.Codeunit.al
@@ -0,0 +1,64 @@
+codeunit 50170 "Purchase Alloc. Acc. Mgt."
+{
+    Access = Public;
+
+    procedure DistributeAmount(PurchaseLine: Record "Purchase Line")
+    var
+        PurchaseHeader: Record "Purchase Header";
+        AllocationAccount: Record "Allocation Account";
+    begin
+        // Bad: Get before guard — wasted DB call when allocation not set
+        PurchaseHeader.Get(PurchaseLine."Document Type", PurchaseLine."Document No.");
+
+        // Guard condition - should be checked first
+        if PurchaseLine."Selected Alloc. Account No." = '' then
+            exit;
+
+        // Validate allocation account exists
+        if not AllocationAccount.Get(PurchaseLine."Selected Alloc. Account No.") then
+            Error('Allocation account %1 does not exist.', PurchaseLine."Selected Alloc. Account No.");
+
+        // Validate account is active
+        AllocationAccount.TestField(Blocked, false);
+
+        // Perform the distribution
+        DistributeToAllocAccount(PurchaseHeader, PurchaseLine, AllocationAccount);
+
+        // Update line with distribution status
+        UpdateLineDistributionStatus(PurchaseLine);
+    end;
+
+    procedure ValidateAllocationSetup(PurchaseLine: Record "Purchase Line"): Boolean
+    var
+        AllocationAccount: Record "Allocation Account";
+    begin
+        if PurchaseLine."Selected Alloc. Account No." = '' then
+            exit(false);
+
+        if not AllocationAccount.Get(PurchaseLine."Selected Alloc. Account No.") then
+            exit(false);
+
+        exit(not AllocationAccount.Blocked);
+    end;
+
+    local procedure DistributeToAllocAccount(PurchaseHeader: Record "Purchase Header"; PurchaseLine: Record "Purchase Line"; AllocationAccount: Record "Allocation Account")
+    var
+        PurchaseLineAllocation: Record "Purchase Line - Alloc. Acc.";
+    begin
+        // Create distribution entries
+        PurchaseLineAllocation.Init();
+        PurchaseLineAllocation."Document Type" := PurchaseLine."Document Type";
+        PurchaseLineAllocation."Document No." := PurchaseLine."Document No.";
+        PurchaseLineAllocation."Line No." := PurchaseLine."Line No.";
+        PurchaseLineAllocation."Allocation Account No." := AllocationAccount."No.";
+        PurchaseLineAllocation.Amount := PurchaseLine."Line Amount";
+        PurchaseLineAllocation.Insert();
+    end;
+
+    local procedure UpdateLineDistributionStatus(var PurchaseLine: Record "Purchase Line")
+    begin
+        PurchaseLine."Alloc. Acc. Distribution Date" := Today();
+        PurchaseLine."Distribution Complete" := true;
+        PurchaseLine.Modify();
+    end;
+}
diff --git a/src/SKUMgt.Codeunit.al b/src/SKUMgt.Codeunit.al
