+codeunit 50171 "SKU Management"
+{
+    Access = Public;
+
+    procedure CheckSKUCreationPolicy(LocationCode: Code[10]): Boolean
+    var
+        Location: Record Location;
+    begin
+        if LocationCode = '' then
+            exit(false);
+
+        Location.Get(LocationCode);
+        Location.TestField("SKU Creation Policy");
+
+        exit(Location."SKU Creation Policy" <> Location."SKU Creation Policy"::Never);
+    end;
+
+    procedure CreateSKUForItem(ItemNo: Code[20]; LocationCode: Code[10])
+    var
+        Item: Record Item;
+        StockkeepingUnit: Record "Stockkeeping Unit";
+    begin
+        if (ItemNo = '') or (LocationCode = '') then
+            exit;
+
+        if not CheckSKUCreationPolicy(LocationCode) then
+            Error('SKU creation is not allowed for location %1', LocationCode);
+
+        Item.SetLoadFields(Description, "Unit Cost", "Standard Cost");
+        Item.Get(ItemNo);
+
+        if StockkeepingUnit.Get(LocationCode, ItemNo, '') then
+            exit;
+
+        StockkeepingUnit.Init();
+        StockkeepingUnit."Location Code" := LocationCode;
+        StockkeepingUnit."Item No." := ItemNo;
+        StockkeepingUnit."Variant Code" := '';
+        StockkeepingUnit.Description := Item.Description;
+        StockkeepingUnit."Unit Cost" := Item."Unit Cost";
+        StockkeepingUnit."Standard Cost" := Item."Standard Cost";
+        StockkeepingUnit.Insert();
+
+        LogSKUCreation(ItemNo, LocationCode);
+    end;
+
+    procedure GetSKUPolicy(LocationCode: Code[10]): Integer
+    var
+        Location: Record Location;
+    begin
+        if LocationCode = '' then
+            exit(0);
+
+        Location.SetLoadFields("SKU Creation Policy");
+        if Location.Get(LocationCode) then
+            exit(Location."SKU Creation Policy".AsInteger());
+        exit(0);
+    end;
+
+    local procedure LogSKUCreation(ItemNo: Code[20]; LocationCode: Code[10])
+    begin
+        // Log SKU creation for audit purposes
+    end;
+}

