@@ -0,0 +1,69 @@
+codeunit 50401 "Report Builder"
+{
+    Access = Public;
+
+    procedure BuildCsvExport(CustomerNo: Code[20]): Text
+    var
+        SalesLine: Record "Sales Line";
+        Result: Text;
+    begin
+        SalesLine.SetRange("Sell-to Customer No.", CustomerNo);
+        SalesLine.SetRange("Document Type", SalesLine."Document Type"::Order);
+        SalesLine.SetLoadFields("No.", Description, Quantity, "Line Amount");
+        Result := 'Item No.,Description,Quantity,Amount';
+        if SalesLine.FindSet() then
+            repeat
+                Result += Format(SalesLine."No.") + ',' +
+                    SalesLine.Description + ',' +
+                    Format(SalesLine.Quantity) + ',' +
+                    Format(SalesLine."Line Amount");
+            until SalesLine.Next() = 0;
+        exit(Result);
+    end;
+
+    procedure BuildHtmlNotification(VendorNo: Code[20]): Text
+    var
+        VendorLedgerEntry: Record "Vendor Ledger Entry";
+        HtmlBody: Text;
+    begin
+        HtmlBody := '<html><body><table>';
+        HtmlBody += '<tr><th>Entry No.</th><th>Description</th><th>Amount</th></tr>';
+        VendorLedgerEntry.SetRange("Vendor No.", VendorNo);
+        VendorLedgerEntry.SetRange(Open, true);
+        VendorLedgerEntry.SetLoadFields(Description);
+        if VendorLedgerEntry.FindSet() then
+            repeat
+                VendorLedgerEntry.CalcFields("Remaining Amount");
+                HtmlBody += '<tr><td>' + Format(VendorLedgerEntry."Entry No.") + '</td>' +
+                    '<td>' + VendorLedgerEntry.Description + '</td>' +
+                    '<td>' + Format(VendorLedgerEntry."Remaining Amount") + '</td></tr>';
+            until VendorLedgerEntry.Next() = 0;
+        HtmlBody += '</table></body></html>';
+        exit(HtmlBody);
+    end;
+
+    procedure BuildItemSummary(LocationCode: Code[10]): Text
+    var
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        Summary: TextBuilder;
+    begin
+        Summary.Append('Location: ' + LocationCode);
+        Summary.AppendLine();
+        Summary.Append('Item No. | Description | Quantity');
+        Summary.AppendLine();
+        ItemLedgerEntry.SetRange("Location Code", LocationCode);
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Purchase);
+        ItemLedgerEntry.SetLoadFields("Item No.", Description, Quantity);
+        if ItemLedgerEntry.FindSet() then
+            repeat
+                Summary.Append(ItemLedgerEntry."Item No.");
+                Summary.Append(' | ');
+                Summary.Append(ItemLedgerEntry.Description);
+                Summary.Append(' | ');
+                Summary.Append(Format(ItemLedgerEntry.Quantity));
+                Summary.AppendLine();
+            until ItemLedgerEntry.Next() = 0;
