+codeunit 50320 "Item Migrator"
+{
+    procedure MigrateItemDescriptions()
+    var
+        Item: Record Item;
+    begin
+        Item.SetFilter(Description, '<>%1', '');
+        if Item.FindSet(true) then
+            repeat
+                Item.Description := ConvertToNewFormat(Item.Description);
+                // Performance issue: Modify(true) fires OnModify trigger per record
+                // Item table can have 800k records — triggers run 800k times
+                Item.Modify(true);
+            until Item.Next() = 0;
+    end;
+
+    local procedure ConvertToNewFormat(OldDesc: Text[100]): Text[100]
+    begin
+        exit(OldDesc.TrimEnd());
+    end;
+}
