+codeunit 50117 "Business Integration Events"
+{
+    Access = Internal;
+    Permissions = tabledata "Business Entity" = m;
+
+    [IntegrationEvent(true, false)]
+    local procedure OnBeforeProcessBusinessEntity(var BusinessEntity: Record "Business Entity"; var IsHandled: Boolean)
+    begin
+    end;
+
+    procedure ProcessBusinessEntityBatch(var BusinessEntityBuffer: Record "Business Entity" temporary)
+    var
+        IsHandled: Boolean;
+        ProcessedCount: Integer;
+    begin
+        if BusinessEntityBuffer.FindSet() then
+            repeat
+                IsHandled := false;
+                OnBeforeProcessBusinessEntity(BusinessEntityBuffer, IsHandled);
+                if not IsHandled then begin
+                    ProcessSingleBusinessEntity(BusinessEntityBuffer);
+                    ProcessedCount += 1;
+                end;
+                OnAfterBusinessEntityProcessed(BusinessEntityBuffer."Entity No.", ProcessedCount);
+            until BusinessEntityBuffer.Next() = 0;
+    end;
+
+    [IntegrationEvent(true, false)]
+    local procedure OnAfterBusinessEntityProcessed(EntityNo: Code[20]; ProcessedCount: Integer)
+    begin
+    end;
+
+    local procedure ProcessSingleBusinessEntity(var BusinessEntity: Record "Business Entity")
+    begin
+        BusinessEntity."Processing Status" := BusinessEntity."Processing Status"::Processed;
+        BusinessEntity."Processed Date" := Today;
+        BusinessEntity.Modify(true);
+    end;
+}

