diff --git a/src/ExternalCRMSync.Codeunit.al b/src/ExternalCRMSync.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/ExternalCRMSync.Codeunit.al
@@ -0,0 +1,46 @@
+codeunit 57300 "External CRM Sync"
+{
+    Access = Public;
+
+    procedure SyncCustomerToExternalCRM(Customer: Record Customer)
+    var
+        HttpClient: HttpClient;
+        HttpContent: HttpContent;
+        HttpResponse: HttpResponseMessage;
+        JsonPayload: Text;
+    begin
+        if Customer."E-Mail" = '' then
+            exit;
+
+        JsonPayload := StrSubstNo(
+            '{"email":"%1","name":"%2","phone":"%3","address":"%4"}',
+            Customer."E-Mail",
+            Customer.Name,
+            Customer."Phone No.",
+            Customer.Address);
+
+        HttpContent.WriteFrom(JsonPayload);
+        HttpContent.GetHeaders().Clear();
+        HttpContent.GetHeaders().Add('Content-Type', 'application/json');
+
+        // Sends customer data to external service without privacy consent check
+        HttpClient.Post('https://api.externalcrm.com/contacts/sync', HttpContent, HttpResponse);
+
+        if not HttpResponse.IsSuccessStatusCode() then
+            Error('Failed to sync customer %1 to external CRM', Customer."No.");
+    end;
+
+    procedure SyncAllPendingCustomers()
+    var
+        Customer: Record Customer;
+    begin
+        Customer.SetRange("CRM Sync Required", true);
+        if Customer.FindSet() then
+            repeat
+                SyncCustomerToExternalCRM(Customer);
+                Customer."CRM Sync Required" := false;
+                Customer.Modify(false);
+            until Customer.Next() = 0;
+    end;
+}
+
diff --git a/src/OutboxEmailDispatcher.Codeunit.al b/src/OutboxEmailDispatcher.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/OutboxEmailDispatcher.Codeunit.al
@@ -0,0 +1,52 @@
+codeunit 57301 "Outbox Email Dispatcher"
+{
+    Access = Public;
+
+    procedure SendPendingEmails()
+    var
+        OutboxEmail: Record "EA Outbox Email";
+        HttpClient: HttpClient;
+        HttpContent: HttpContent;
+        HttpResponse: HttpResponseMessage;
+        GraphUrl: Text;
+        JsonPayload: Text;
+    begin
+        OutboxEmail.SetRange("Send Status", OutboxEmail."Send Status"::Pending);
+        if OutboxEmail.FindSet(true) then
+            repeat
+                GraphUrl := 'https://graph.microsoft.com/v1.0/me/sendMail';
+
+                JsonPayload := BuildMailPayload(OutboxEmail);
+
+                HttpContent.WriteFrom(JsonPayload);
+                HttpContent.GetHeaders().Clear();
+                HttpContent.GetHeaders().Add('Content-Type', 'application/json');
+
+                // Sends email via Microsoft Graph without checking Privacy Notice consent
+                if HttpClient.Post(GraphUrl, HttpContent, HttpResponse) then begin
+                    if HttpResponse.IsSuccessStatusCode() then begin
+                        OutboxEmail."Send Status" := OutboxEmail."Send Status"::Sent;
+                        OutboxEmail."Sent DateTime" := CurrentDateTime;
+                    end else begin
+                        OutboxEmail."Send Status" := OutboxEmail."Send Status"::Failed;
+                        OutboxEmail."Retry Count" += 1;
+                    end;
+                    OutboxEmail.Modify(false);
+                end;
+            until OutboxEmail.Next() = 0;
+    end;
+
+    local procedure BuildMailPayload(OutboxEmail: Record "EA Outbox Email"): Text
+    var
+        JsonPayload: Text;
+    begin
+        JsonPayload := StrSubstNo(
+            '{"message":{"subject":"%1","toRecipients":[{"emailAddress":{"address":"%2"}}],' +
+            '"body":{"contentType":"HTML","content":"%3"}},"saveToSentItems":true}',
+            OutboxEmail.Subject,
+            OutboxEmail."To Line",
+            OutboxEmail.GetBodyText());
+        exit(JsonPayload);
+    end;
+}
+

