+    local procedure BuildMailPayload(OutboxEmail: Record "EA Outbox Email"): Text
+    var
+        Message: JsonObject;
+        Body: JsonObject;
+        Recipient: JsonObject;
+        EmailAddress: JsonObject;
+        ToRecipients: JsonArray;
+        Root: JsonObject;
+        PayloadText: Text;
