diff --git a/src/AgentTaskTemplate.Codeunit.al b/src/AgentTaskTemplate.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/AgentTaskTemplate.Codeunit.al
@@ -0,0 +1,131 @@
+codeunit 50105 "Agent Task Template"
+{
+    Access = Public;
+
+    var
+        TempBlob: Codeunit "Temp Blob";
+        TemplateStream: InStream;
+        TemplateOutStream: OutStream;
+
+    procedure ImportTemplate(FilePath: Text): Boolean
+    var
+        FileManagement: Codeunit "File Management";
+        ImportFile: File;
+        ImportInStream: InStream;
+        TemplateRecord: Record "Agent Template";
+        TemplateExists: Boolean;
+        ValidationResult: Boolean;
+        ProcessingError: Text;
+        ImportSuccess: Boolean;
+        DocumentType: Text;
+        DocumentVersion: Text;
+        DocumentContent: Text;
+        ProcessingOptions: Record "Template Processing Options";
+        FieldMapping: Record "Field Mapping";
+        ValidationRules: Record "Validation Rules";
+        TransformationRules: Record "Transformation Rules";
+        OutputConfiguration: Record "Output Configuration";
+        LoggingOptions: Record "Logging Options";
+        SecuritySettings: Record "Security Settings";
+        PerformanceSettings: Record "Performance Settings";
+        ErrorHandlingSettings: Record "Error Handling Settings";
+        NotificationSettings: Record "Notification Settings";
+
+    begin  // begin keyword at line 78 - but more variables after
+        // Initialize processing
+        ImportSuccess := false;
+        DocumentType := '';
+
+        if not FileExists(FilePath) then begin
+            ProcessingError := 'File does not exist: ' + FilePath;
+            exit(false);
+        end;
+
+        // Additional variable declarations after begin (lines 87-92)
+        return ImportTemplateFromStream(ImportInStream, DocumentType, ValidationResult);
+    end;
+
+    local procedure ImportTemplateFromStream(var ImportStream: InStream; DocumentType: Text; var ValidationResult: Boolean): Boolean
+    var
+        StreamReader: Codeunit "Stream Reader";
+        JsonParser: Codeunit "JSON Parser";
+        TemplateValidator: Codeunit "Template Validator";
+        ContentBuffer: Text;
+        ParseResult: Boolean;
+    begin
+        ValidationResult := false;
+
+        if ImportStream.EOS() then
+            exit(false);
+
+        StreamReader.ReadText(ImportStream, ContentBuffer);
+        if ContentBuffer = '' then
+            exit(false);
+
+        ParseResult := JsonParser.Parse(ContentBuffer);
+        if not ParseResult then
+            exit(false);
+
+        ValidationResult := TemplateValidator.ValidateTemplate(ContentBuffer);
+        exit(ValidationResult);
+    end;
+
+    procedure ExportTemplate(TemplateCode: Code[20]; FilePath: Text): Boolean
+    var
+        TemplateRecord: Record "Agent Template";
+        FileManagement: Codeunit "File Management";
+        ExportFile: File;
+        ExportOutStream: OutStream;
+        JsonBuilder: Codeunit "JSON Builder";
+        ExportContent: Text;
+    begin
+        if not TemplateRecord.Get(TemplateCode) then
+            exit(false);
+
+        ExportContent := JsonBuilder.BuildTemplateJson(TemplateRecord);
+        if ExportContent = '' then
+            exit(false);
+
+        ExportFile.Create(FilePath);
+        ExportFile.CreateOutStream(ExportOutStream);
+        ExportOutStream.WriteText(ExportContent);
+        ExportFile.Close();
+
+        exit(FileExists(FilePath));
+    end;
+
+    procedure ValidateTemplate(TemplateCode: Code[20]): Boolean
+    var
+        TemplateRecord: Record "Agent Template";
+        ValidationEngine: Codeunit "Validation Engine";
+        ValidationErrors: List of [Text];
+        IsValid: Boolean;
+    begin
+        if not TemplateRecord.Get(TemplateCode) then
+            exit(false);
+
+        IsValid := ValidationEngine.ValidateTemplateStructure(TemplateRecord, ValidationErrors);
+        if not IsValid then begin
+            LogValidationErrors(ValidationErrors);
+            exit(false);
+        end;
+
+        exit(true);
+    end;
+
+    local procedure LogValidationErrors(ValidationErrors: List of [Text])
+    var
+        ErrorText: Text;
+    begin
+        foreach ErrorText in ValidationErrors do
+            Session.LogMessage('Template Validation', ErrorText, Verbosity::Error, DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, 'Category', 'TemplateValidation');
+    end;
+
+    local procedure FileExists(FilePath: Text): Boolean
+    var
+        FileManagement: Codeunit "File Management";
+    begin
+        exit(FileManagement.ServerFileExists(FilePath));
+    end;
+}
+
diff --git a/src/NonDeductiblePurchPosting.Codeunit.al b/src/NonDeductiblePurchPosting.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/NonDeductiblePurchPosting.Codeunit.al
@@ -0,0 +1,235 @@
+codeunit 50108 "Non-Deductible Purch. Posting"
+{
+    Access = Public;
+
+    var
+        GeneralLedgerSetup: Record "General Ledger Setup";
+        VATPostingSetup: Record "VAT Posting Setup";
+        TempItemLedgerEntry: Record "Item Ledger Entry" temporary;
+
+    procedure PostNonDeductibleVAT(var PurchaseHeader: Record "Purchase Header"): Boolean
+    var
+        PurchaseLine: Record "Purchase Line";
+        VATEntry: Record "VAT Entry";
+        GenJournalLine: Record "Gen. Journal Line";
+        PostingResult: Boolean;
+        TotalNonDeductibleVAT: Decimal;
+        LineNonDeductibleVAT: Decimal;
+        VATAmount: Decimal;
+        NonDeductiblePercent: Decimal;
+        EntryNo: Integer;
+    begin
+        PostingResult := true;
+        TotalNonDeductibleVAT := 0;
+
+        if not ValidateDocumentForProcessing(PurchaseHeader) then
+            exit(false);
+
+        PurchaseLine.SetRange("Document Type", PurchaseHeader."Document Type");
+        PurchaseLine.SetRange("Document No.", PurchaseHeader."No.");
+        PurchaseLine.SetFilter("VAT %", '>0');
+
+        if PurchaseLine.FindSet() then
+            repeat
+                if GetVATPostingSetup(PurchaseLine) then begin
+                    NonDeductiblePercent := VATPostingSetup."Non-Deductible VAT %";
+                    if NonDeductiblePercent > 0 then begin
+                        VATAmount := CalculateVATAmount(PurchaseLine);
+                        LineNonDeductibleVAT := Round(VATAmount * NonDeductiblePercent / 100);
+
+                        if LineNonDeductibleVAT <> 0 then begin
+                            PostingResult := PostNonDeductibleVATEntry(PurchaseLine, LineNonDeductibleVAT);
+                            if PostingResult then
+                                TotalNonDeductibleVAT += LineNonDeductibleVAT
+                            else
+                                exit(false);
+                        end;
+                    end;
+                end;
+            until PurchaseLine.Next() = 0;
+
+        // Update document totals if processing was successful
+        if PostingResult and (TotalNonDeductibleVAT <> 0) then
+            UpdateDocumentTotals(PurchaseHeader, TotalNonDeductibleVAT);
+
+        exit(PostingResult);
+    end;
+
+    local procedure ValidateDocumentForProcessing(var PurchaseHeader: Record "Purchase Header"): Boolean
+    var
+        PurchaseLine: Record "Purchase Line";
+        Vendor: Record Vendor;
+        ValidationResult: Boolean;
+    begin
+        ValidationResult := true;
+
+        // Validate vendor exists
+        if not Vendor.Get(PurchaseHeader."Buy-from Vendor No.") then
+            exit(false);
+
+        // Validate lines exist
+        PurchaseLine.SetRange("Document Type", PurchaseHeader."Document Type");
+        PurchaseLine.SetRange("Document No.", PurchaseHeader."No.");
+        if PurchaseLine.IsEmpty() then
+            exit(false);
+
+        exit(ValidationResult);
+    end;
+
+    local procedure GetVATPostingSetup(PurchaseLine: Record "Purchase Line"): Boolean
+    begin
+        if VATPostingSetup.Get(PurchaseLine."VAT Bus. Posting Group", PurchaseLine."VAT Prod. Posting Group") then
+            exit(true)
+        else
+            exit(false);
+    end;
+
+    local procedure CalculateVATAmount(PurchaseLine: Record "Purchase Line"): Decimal
+    var
+        LineAmount: Decimal;
+        VATAmount: Decimal;
+    begin
+        LineAmount := PurchaseLine."Line Amount";
+        if PurchaseLine."VAT Calculation Type" = PurchaseLine."VAT Calculation Type"::"Normal VAT" then
+            VATAmount := Round(LineAmount * PurchaseLine."VAT %" / 100)
+        else
+            VATAmount := PurchaseLine."Amount Including VAT" - PurchaseLine.Amount;
+
+        exit(VATAmount);
+    end;
+
+    local procedure PostNonDeductibleVATEntry(PurchaseLine: Record "Purchase Line"; NonDeductibleAmount: Decimal): Boolean
+    var
+        VATEntry: Record "VAT Entry";
+        GenJournalLine: Record "Gen. Journal Line";
+        GenJournalPostLine: Codeunit "Gen. Jnl.-Post Line";
+        NonDeductibleAccount: Code[20];
+        PostingSuccess: Boolean;
+    begin
+        PostingSuccess := false;
+
+        // Get the non-deductible VAT account
+        if not GetNonDeductibleVATAccount(PurchaseLine, NonDeductibleAccount) then
+            exit(false);
+
+        // Create journal line for non-deductible VAT
+        GenJournalLine.Init();
+        GenJournalLine."Document Type" := GenJournalLine."Document Type"::Invoice;
+        GenJournalLine."Document No." := PurchaseLine."Document No.";
+        GenJournalLine."Posting Date" := WorkDate();
+        GenJournalLine."Account Type" := GenJournalLine."Account Type"::"G/L Account";
+        GenJournalLine."Account No." := NonDeductibleAccount;
+        GenJournalLine.Amount := NonDeductibleAmount;
+        GenJournalLine."Currency Code" := PurchaseLine."Currency Code";
+        GenJournalLine."VAT Bus. Posting Group" := PurchaseLine."VAT Bus. Posting Group";
+        GenJournalLine."VAT Prod. Posting Group" := PurchaseLine."VAT Prod. Posting Group";
+        GenJournalLine.Description := 'Non-Deductible VAT - ' + PurchaseLine."No.";
+
+        // Validate amounts and setup
+        if ValidateJournalLine(GenJournalLine) then begin
+            begin  // Unnecessary BEGIN..END for compound statement - line 866
+                if CheckPostingPermissions(GenJournalLine) then begin
+                    PostingSuccess := GenJournalPostLine.RunWithCheck(GenJournalLine);
+                    if PostingSuccess then
+                        CreateVATEntry(GenJournalLine, NonDeductibleAmount);
+                end;
+            end
+            else begin
+                PostingSuccess := false;
+            end;
+
+            exit(PostingSuccess);
+        end;
+
+        local procedure GetNonDeductibleVATAccount(PurchaseLine: Record "Purchase Line"; var AccountNo: Code[20]): Boolean
+    begin
+        if VATPostingSetup.Get(PurchaseLine."VAT Bus. Posting Group", PurchaseLine."VAT Prod. Posting Group") then begin
+            AccountNo := VATPostingSetup."Non-Deductible VAT Account";
+            exit(AccountNo <> '');
+        end;
+        exit(false);
+    end;
+
+    local procedure ValidateJournalLine(GenJournalLine: Record "Gen. Journal Line"): Boolean
+    var
+        GLAccount: Record "G/L Account";
+        IsValid: Boolean;
+    begin
+        IsValid := true;
+
+        // Validate account exists and is active
+        if not GLAccount.Get(GenJournalLine."Account No.") then
+            exit(false);
+
+        if GLAccount.Blocked then
+            exit(false);
+
+        // Validate amount
+        if GenJournalLine.Amount = 0 then
+            exit(false);
+
+        // Validate posting date
+        if GenJournalLine."Posting Date" = 0D then
+            exit(false);
+
+        exit(IsValid);
+    end;
+
+    local procedure CheckPostingPermissions(GenJournalLine: Record "Gen. Journal Line"): Boolean
+    var
+        UserSetup: Record "User Setup";
+        HasPermission: Boolean;
+    begin
+        HasPermission := true;
+
+        // Check if user has permission to post to the specified account
+        if UserSetup.Get(UserId()) then begin
+            if UserSetup."Allow Posting From" <> 0D then
+                if GenJournalLine."Posting Date" < UserSetup."Allow Posting From" then
+                    HasPermission := false;
+
+            if UserSetup."Allow Posting To" <> 0D then
+                if GenJournalLine."Posting Date" > UserSetup."Allow Posting To" then
+                    HasPermission := false;
+        end;
+
+        exit(HasPermission);
+    end;
+
+    local procedure CreateVATEntry(GenJournalLine: Record "Gen. Journal Line"; VATAmount: Decimal)
+    var
+        VATEntry: Record "VAT Entry";
+        EntryNo: Integer;
+    begin
+        VATEntry.Init();
+
+        // Get next entry number
+        VATEntry.SetCurrentKey("Entry No.");
+        if VATEntry.FindLast() then
+            EntryNo := VATEntry."Entry No." + 1
+        else
+            EntryNo := 1;
+
+        VATEntry."Entry No." := EntryNo;
+        VATEntry."Gen. Bus. Posting Group" := GenJournalLine."Gen. Bus. Posting Group";
+        VATEntry."Gen. Prod. Posting Group" := GenJournalLine."Gen. Prod. Posting Group";
+        VATEntry."VAT Bus. Posting Group" := GenJournalLine."VAT Bus. Posting Group";
+        VATEntry."VAT Prod. Posting Group" := GenJournalLine."VAT Prod. Posting Group";
+        VATEntry."Posting Date" := GenJournalLine."Posting Date";
+        VATEntry."Document No." := GenJournalLine."Document No.";
+        VATEntry."Document Type" := GenJournalLine."Document Type";
+        VATEntry.Amount := VATAmount;
+        VATEntry.Type := VATEntry.Type::Purchase;
+        VATEntry."Non-Deductible VAT Base" := VATAmount;
+        VATEntry."User ID" := CopyStr(UserId(), 1, MaxStrLen(VATEntry."User ID"));
+        VATEntry."Source Code" := 'PURCHASES';
+        VATEntry.Insert(true);
+    end;
+
+    local procedure UpdateDocumentTotals(var PurchaseHeader: Record "Purchase Header"; NonDeductibleAmount: Decimal)
+    begin
+        PurchaseHeader."Non-Deductible VAT Amount" := NonDeductibleAmount;
+        PurchaseHeader.Modify(true);
+    end;
+}
+
