diff --git a/src/CloudMigReplicateDataMgt.Codeunit.al b/src/CloudMigReplicateDataMgt.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/CloudMigReplicateDataMgt.Codeunit.al
@@ -0,0 +1,235 @@
+codeunit 50117 "Cloud Mig. Replicate Data Mgt"
+{
+    Access = Public;
+
+    var
+        TablesCannotBeEnabledForReplicationErr: Label 'The following tables cannot be enabled for replication because they contain sensitive data or are system tables:%1\\Please review the table selection and remove any tables that should not be replicated to ensure data security and compliance with privacy regulations.', Comment = '%1 = List of table names';
+
+    procedure ValidateTablesForReplication(var TableList: Record "Cloud Migration Table" temporary): Boolean
+    var
+        RestrictedTables: List of [Text];
+        RestrictedTableNames: Text;
+        TableName: Text;
+        ValidationPassed: Boolean;
+    begin
+        ValidationPassed := true;
+
+        if TableList.FindSet() then
+            repeat
+                if IsTableRestrictedForReplication(TableList."Table ID") then begin
+                    TableName := GetTableName(TableList."Table ID");
+                    RestrictedTables.Add(TableName);
+                    ValidationPassed := false;
+                end;
+            until TableList.Next() = 0;
+
+        if not ValidationPassed then begin
+            RestrictedTableNames := BuildRestrictedTableList(RestrictedTables);
+            Error(TablesCannotBeEnabledForReplicationErr, RestrictedTableNames);  // Line 603
+        end;
+
+        exit(ValidationPassed);
+    end;
+
+    procedure EnableReplicationForTables(var TableList: Record "Cloud Migration Table" temporary)
+    var
+        CloudMigrationSetup: Record "Cloud Migration Setup";
+        ReplicationSetup: Record "Replication Setup";
+        TableCount: Integer;
+        EnabledCount: Integer;
+    begin
+        if not ValidateTablesForReplication(TableList) then
+            exit;
+
+        if not CloudMigrationSetup.Get() then begin
+            CloudMigrationSetup.Init();
+            CloudMigrationSetup.Insert(true);
+        end;
+
+        TableCount := TableList.Count();
+
+        if TableList.FindSet() then
+            repeat
+                if EnableTableReplication(TableList."Table ID") then begin
+                    TableList."Replication Enabled" := true;
+                    TableList.Modify();
+                    EnabledCount += 1;
+                end;
+            until TableList.Next() = 0;
+
+        Message('Replication enabled for %1 of %2 tables', EnabledCount, TableCount);
+    end;
+
+    local procedure IsTableRestrictedForReplication(TableID: Integer): Boolean
+    var
+        RestrictedTables: List of [Integer];
+        IsRestricted: Boolean;
+    begin
+        // Define restricted table IDs
+        RestrictedTables.Add(2000000001); // User
+        RestrictedTables.Add(2000000002); // User Property
+        RestrictedTables.Add(2000000120); // User Personalization
+        RestrictedTables.Add(50001); // User Authentication
+        RestrictedTables.Add(50002); // Security Token
+        RestrictedTables.Add(50003); // Encryption Key
+        RestrictedTables.Add(18); // Customer
+        RestrictedTables.Add(23); // Vendor
+
+        IsRestricted := RestrictedTables.Contains(TableID);
+
+        // Additional checks for sensitive data
+        if not IsRestricted then
+            IsRestricted := ContainsSensitiveData(TableID);
+
+        exit(IsRestricted);
+    end;
+
+    local procedure ContainsSensitiveData(TableID: Integer): Boolean
+    var
+        TableMetadata: Record "Table Metadata";
+        FieldMetadata: Record "Field Metadata";
+        HasSensitiveFields: Boolean;
+    begin
+        HasSensitiveFields := false;
+
+        if TableMetadata.Get(TableID) then begin
+            FieldMetadata.SetRange(TableNo, TableID);
+            FieldMetadata.SetFilter(DataClassification, '%1|%2|%3',
+                'CustomerContent',
+                'EndUserIdentifiableInformation',
+                'EndUserPseudonymousIdentifiers');
+
+            HasSensitiveFields := not FieldMetadata.IsEmpty();
+        end;
+
+        exit(HasSensitiveFields);
+    end;
+
+    local procedure GetTableName(TableID: Integer): Text
+    var
+        TableMetadata: Record "Table Metadata";
+        TableName: Text;
+    begin
+        if TableMetadata.Get(TableID) then
+            TableName := TableMetadata.Name
+        else
+            TableName := 'Unknown Table (' + Format(TableID) + ')';
+
+        exit(TableName);
+    end;
+
+    local procedure BuildRestrictedTableList(RestrictedTables: List of [Text]): Text
+    var
+        TableNames: Text;
+        TableName: Text;
+        Separator: Text;
+    begin
+        Separator := '';
+
+        foreach TableName in RestrictedTables do begin
+            TableNames := TableNames + Separator + '- ' + TableName;
+            Separator := '\';
+        end;
+
+        exit(TableNames);
+    end;
+
+    local procedure EnableTableReplication(TableID: Integer): Boolean
+    var
+        ReplicationSetup: Record "Replication Setup";
+        TableMetadata: Record "Table Metadata";
+        EnableSuccess: Boolean;
+    begin
+        EnableSuccess := false;
+
+        if TableMetadata.Get(TableID) then begin
+            if not ReplicationSetup.Get(TableID) then begin
+                ReplicationSetup.Init();
+                ReplicationSetup."Table ID" := TableID;
+                ReplicationSetup."Table Name" := TableMetadata.Name;
+                ReplicationSetup."Replication Enabled" := true;
+                ReplicationSetup."Last Modified" := CurrentDateTime();
+                EnableSuccess := ReplicationSetup.Insert(true);
+            end else begin
+                ReplicationSetup."Replication Enabled" := true;
+                ReplicationSetup."Last Modified" := CurrentDateTime();
+                EnableSuccess := ReplicationSetup.Modify(true);
+            end;
+        end;
+
+        exit(EnableSuccess);
+    end;
+
+    procedure GetReplicationStatus(var TempReplicationStatus: Record "Replication Status" temporary)
+    var
+        ReplicationSetup: Record "Replication Setup";
+        ReplicationStatus: Record "Replication Status";
+    begin
+        TempReplicationStatus.Reset();
+        TempReplicationStatus.DeleteAll();
+
+        ReplicationSetup.SetRange("Replication Enabled", true);
+
+        if ReplicationSetup.FindSet() then
+            repeat
+                TempReplicationStatus.Init();
+                TempReplicationStatus."Table ID" := ReplicationSetup."Table ID";
+                TempReplicationStatus."Table Name" := ReplicationSetup."Table Name";
+                TempReplicationStatus."Replication Enabled" := ReplicationSetup."Replication Enabled";
+                TempReplicationStatus."Last Sync Date" := GetLastSyncDate(ReplicationSetup."Table ID");
+                TempReplicationStatus."Record Count" := GetTableRecordCount(ReplicationSetup."Table ID");
+                TempReplicationStatus."Status" := GetReplicationStatusText(ReplicationSetup."Table ID");
+                TempReplicationStatus.Insert();
+            until ReplicationSetup.Next() = 0;
+    end;
+
+    local procedure GetLastSyncDate(TableID: Integer): DateTime
+    var
+        SyncLog: Record "Cloud Migration Sync Log";
+        LastSyncDate: DateTime;
+    begin
+        SyncLog.SetRange("Table ID", TableID);
+        SyncLog.SetCurrentKey("Sync Date");
+        SyncLog.SetAscending("Sync Date", false);
+
+        if SyncLog.FindFirst() then
+            LastSyncDate := SyncLog."Sync Date"
+        else
+            LastSyncDate := 0DT;
+
+        exit(LastSyncDate);
+    end;
+
+    local procedure GetTableRecordCount(TableID: Integer): Integer
+    var
+        RecRef: RecordRef;
+        RecordCount: Integer;
+    begin
+        RecordCount := 0;
+
+        if RecRef.Open(TableID) then begin
+            RecordCount := RecRef.Count();
+            RecRef.Close();
+        end;
+
+        exit(RecordCount);
+    end;
+
+    local procedure GetReplicationStatusText(TableID: Integer): Text[50]
+    var
+        StatusText: Text[50];
+        LastSyncDate: DateTime;
+    begin
+        LastSyncDate := GetLastSyncDate(TableID);
+
+        if LastSyncDate = 0DT then
+            StatusText := 'Never Synced'
+        else if LastSyncDate < CreateDateTime(CalcDate('<-1D>', Today), 0T) then
+            StatusText := 'Sync Overdue'
+        else
+            StatusText := 'Up to Date';
+
+        exit(StatusText);
+    end;
+}
+
diff --git a/src/CustStPDFDocHandler.Codeunit.al b/src/CustStPDFDocHandler.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/CustStPDFDocHandler.Codeunit.al
@@ -0,0 +1,218 @@
+codeunit 50114 "Cust. St. PDF Doc Handler"
+{
+    Access = Public;
+
+    var
+        TempBlob: Codeunit "Temp Blob";
+        FileManagement: Codeunit "File Management";
+
+        UnableToProcessDocumentErr: Label 'Unable to process document with SystemId %1,', Comment = 'SystemId %1';
+
+    procedure ProcessCustomerStatement(CustomerNo: Code[20]; StatementDate: Date): Boolean
+    var
+        Customer: Record Customer;
+        CustomerStatement: Record "Customer Statement";
+        PDFGenerator: Codeunit "PDF Generator";
+        ProcessingResult: Boolean;
+        DocumentStream: InStream;
+        PDFStream: OutStream;
+        StatementGuid: Guid;
+    begin
+        ProcessingResult := false;
+
+        if not Customer.Get(CustomerNo) then
+            exit(false);
+
+        // Generate statement record
+        CustomerStatement.Init();
+        CustomerStatement."Customer No." := CustomerNo;
+        CustomerStatement."Statement Date" := StatementDate;
+        CustomerStatement."Created Date" := Today;
+        CustomerStatement."Created Time" := Time;
+        CustomerStatement."Created by User" := CopyStr(UserId(), 1, MaxStrLen(CustomerStatement."Created by User"));
+
+        if CustomerStatement.Insert(true) then begin
+            StatementGuid := CustomerStatement.SystemId;
+
+            // Generate PDF content
+            if GeneratePDFContent(CustomerStatement, DocumentStream) then begin
+                if ConvertToPDF(DocumentStream, PDFStream) then begin
+                    CustomerStatement."PDF Generated" := true;
+                    CustomerStatement."PDF Size" := GetStreamSize(PDFStream);
+                    CustomerStatement.Modify(true);
+                    ProcessingResult := true;
+                end else begin
+                    Error(UnableToProcessDocumentErr, StatementGuid);  // Error with trailing comma - line 34
+                end;
+            end else begin
+                Error(UnableToProcessDocumentErr, StatementGuid);
+            end;
+        end else begin
+            Error('Unable to create customer statement record for customer %1', CustomerNo);
+        end;
+
+        exit(ProcessingResult);
+    end;
+
+    local procedure GeneratePDFContent(CustomerStatement: Record "Customer Statement"; var ContentStream: InStream): Boolean
+    var
+        Customer: Record Customer;
+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        ReportSelections: Record "Report Selections";
+        TempReportSelections: Record "Report Selections" temporary;
+        StatementReportID: Integer;
+        ContentGenerated: Boolean;
+        TempFileName: Text;
+        OutStream: OutStream;
+    begin
+        ContentGenerated := false;
+
+        if not Customer.Get(CustomerStatement."Customer No.") then
+            exit(false);
+
+        // Find the appropriate report for customer statements
+        ReportSelections.SetRange(Usage, ReportSelections.Usage::"C.Statement");
+        ReportSelections.SetRange("Report ID", Report::"Standard Statement");
+
+        if ReportSelections.FindFirst() then begin
+            StatementReportID := ReportSelections."Report ID";
+
+            // Create temporary file for report output
+            TempFileName := FileManagement.ServerTempFileName('pdf');
+
+            // Set filters for the report
+            Customer.SetRange("No.", CustomerStatement."Customer No.");
+            CustLedgerEntry.SetRange("Customer No.", CustomerStatement."Customer No.");
+            CustLedgerEntry.SetFilter("Posting Date", '..%1', CustomerStatement."Statement Date");
+
+            // Generate the report
+            if GenerateStatementReport(StatementReportID, Customer, CustLedgerEntry, TempFileName) then begin
+                // Read the generated file into stream
+                if ReadFileToStream(TempFileName, ContentStream) then
+                    ContentGenerated := true;
+
+                // Clean up temporary file
+                if FileManagement.ServerFileExists(TempFileName) then
+                    FileManagement.DeleteServerFile(TempFileName);
+            end;
+        end;
+
+        exit(ContentGenerated);
+    end;
+
+    local procedure GenerateStatementReport(ReportID: Integer; var Customer: Record Customer; var CustLedgerEntry: Record "Cust. Ledger Entry"; OutputFileName: Text): Boolean
+    var
+        GenerationSuccess: Boolean;
+    begin
+        GenerationSuccess := false;
+
+        try
+            Report.SaveAsPdf(ReportID, OutputFileName, Customer, CustLedgerEntry);
+        GenerationSuccess := FileManagement.ServerFileExists(OutputFileName);
+        except
+            GenerationSuccess := false;
+    end;
+        
+        exit(GenerationSuccess);
+    end;
+
+    local procedure ReadFileToStream(FileName: Text; var ContentStream: InStream): Boolean
+    var
+        TempFile: File;
+        ReadSuccess: Boolean;
+    begin
+        ReadSuccess := false;
+        
+        if FileManagement.ServerFileExists(FileName) then begin
+            TempFile.Open(FileName);
+            TempFile.CreateInStream(ContentStream);
+            ReadSuccess := not ContentStream.EOS;
+            TempFile.Close();
+        end;
+        
+        exit(ReadSuccess);
+    end;
+
+    local procedure ConvertToPDF(var InputStream: InStream; var OutputStream: OutStream): Boolean
+    var
+        PDFConverter: Codeunit "PDF Converter";
+        ConversionSuccess: Boolean;
+    begin
+        ConversionSuccess := false;
+        
+        if not InputStream.EOS then begin
+            try
+                TempBlob.CreateOutStream(OutputStream);
+                CopyStream(OutputStream, InputStream);
+                ConversionSuccess := true;
+            except
+                ConversionSuccess := false;
+            end;
+        end;
+        
+        exit(ConversionSuccess);
+    end;
+
+    local procedure GetStreamSize(var Stream: OutStream): Integer
+    var
+        StreamSize: Integer;
+    begin
+        // This is a simplified implementation
+        // In reality, you would measure the actual stream size
+        StreamSize := 0;
+        
+        exit(StreamSize);
+    end;
+
+    procedure ValidateStatementParameters(CustomerNo: Code[20]; StatementDate: Date): Boolean
+    var
+        Customer: Record Customer;
+        ValidationResult: Boolean;
+    begin
+        ValidationResult := true;
+        
+        // Validate customer exists
+        if not Customer.Get(CustomerNo) then begin
+            Error('Customer %1 does not exist', CustomerNo);
+            ValidationResult := false;
+        end;
+        
+        // Validate customer is not blocked
+        if Customer.Blocked <> Customer.Blocked::" " then begin
+            Error('Customer %1 is blocked and cannot have statements generated', CustomerNo);
+            ValidationResult := false;
+        end;
+        
+        // Validate statement date
+        if StatementDate = 0D then begin
+            Error('Statement date must be specified');
+            ValidationResult := false;
+        end;
+        
+        if StatementDate > Today then begin
+            Error('Statement date cannot be in the future');
+            ValidationResult := false;
+        end;
+        
+        exit(ValidationResult);
+    end;
+
+    procedure GetStatementHistory(CustomerNo: Code[20]; var TempStatementHistory: Record "Customer Statement" temporary)
+    var
+        CustomerStatement: Record "Customer Statement";
+    begin
+        TempStatementHistory.Reset();
+        TempStatementHistory.DeleteAll();
+        
+        CustomerStatement.SetRange("Customer No.", CustomerNo);
+        CustomerStatement.SetCurrentKey("Statement Date");
+        CustomerStatement.Ascending(false);
+        
+        if CustomerStatement.FindSet() then
+            repeat
+                TempStatementHistory.Copy(CustomerStatement);
+                TempStatementHistory.Insert();
+            until CustomerStatement.Next() = 0;
+    end;
+}
+
