+        field(6; "Max Amount"; Decimal)
+        {
+            Caption = 'Max Amount';
+            DataClassification = CustomerContent;
+            MinValue = 0;
+
+            trigger OnValidate()
+            begin
+                if "Max Amount" < 0 then
+                    Error('Maximum amount cannot be negative');
+            end;
+        }
+        field(7; "Approval Required"; Boolean)
+        {
+            Caption = 'Approval Required';
+            DataClassification = CustomerContent;
+        }
+        field(8; "Approval Amount Threshold"; Decimal)
+        {
+            Caption = 'Approval Amount Threshold';
+            DataClassification = CustomerContent;
+            MinValue = 0;
+        }
+        field(10; "VAT Bus. Posting Group"; Code[20])
+        {
+            Caption = 'VAT Bus. Posting Group';
+            TableRelation = "VAT Business Posting Group";
+            DataClassification = CustomerContent;
+        }
+        field(11; "VAT Prod. Posting Group"; Code[20])
+        {
+            Caption = 'VAT Prod. Posting Group';
+            TableRelation = "VAT Product Posting Group";
+            DataClassification = CustomerContent;
+        }
+        field(12; "Gen. Bus. Posting Group"; Code[20])
+        {
+            Caption = 'Gen. Bus. Posting Group';
+            TableRelation = "Gen. Business Posting Group";
+            DataClassification = CustomerContent;
+        }
+        field(13; "Gen. Prod. Posting Group"; Code[20])
+        {
+            Caption = 'Gen. Prod. Posting Group';
+            TableRelation = "Gen. Product Posting Group";
+            DataClassification = CustomerContent;
+        }
+        field(20; "Allow Personal Use"; Boolean)
+        {
+            Caption = 'Allow Personal Use';
+            DataClassification = CustomerContent;
+        }
+        field(21; "Personal Use %"; Decimal)
+        {
+            Caption = 'Personal Use %';
+            DataClassification = CustomerContent;
+            DecimalPlaces = 0 : 5;
+            MaxValue = 100;
+            MinValue = 0;
+        }
+        field(30; "Mileage Rate"; Decimal)
+        {
+            Caption = 'Mileage Rate';
+            DataClassification = CustomerContent;
+            AutoFormatType = 2;
+            BlankZero = true;
+        }
+        field(31; "Mileage Unit"; Code[10])
+        {
+            Caption = 'Mileage Unit';
+            TableRelation = "Unit of Measure";
+            DataClassification = CustomerContent;
+        }
+        field(40; "Active"; Boolean)
+        {
+            Caption = 'Active';
+            DataClassification = CustomerContent;
+            InitValue = true;
+        }
+        field(41; "Effective Date"; Date)
+        {
+            Caption = 'Effective Date';
+            DataClassification = CustomerContent;
+        }
+        field(42; "Expiration Date"; Date)
+        {
+            Caption = 'Expiration Date';
+            DataClassification = CustomerContent;
+        }
+    }
+
+    keys
+    {
+        key(PK; Code)
+        {
+            Clustered = true;
+        }
+        key(DescriptionKey; Description)
+        {
+        }
+        key(ExpenseTypeKey; "Expense Type", Code)
+        {
+        }
+        key(ActiveKey; Active, "Effective Date")
+        {
+        }
+    }
+
+    fieldgroups
+    {
+        fieldgroup(DropDown; Code, Description, "Expense Type")
+        {
+        }
+        fieldgroup(Brick; Code, Description, "G/L Account No.", Active)
+        {
+        }
+    }
+
+    trigger OnInsert()
+    begin
+        if "Effective Date" = 0D then
+            "Effective Date" := Today;
+
+        ValidateExpenseCategory();
+    end;
+
+    trigger OnModify()
+    begin
+        ValidateExpenseCategory();
+    end;
+
+    trigger OnDelete()
+    var
+        ExpenseLine: Record "Expense Line";
+    begin
+        // Check if category is used in any expense lines
+        ExpenseLine.SetRange("Expense Category Code", Code);
+        if not ExpenseLine.IsEmpty() then
+            Error('Cannot delete expense category %1 because it is used in expense lines', Code);
+    end;
+
+    local procedure ValidateGLAccount()
+    var
+        GLAccount: Record "G/L Account";
+    begin
+        if "G/L Account No." = '' then
+            exit;
+
+        if not GLAccount.Get("G/L Account No.") then
+            Error('G/L Account %1 does not exist', "G/L Account No.");
+
+        if GLAccount."Account Type" <> GLAccount."Account Type"::Posting then
+            Error('G/L Account %1 must be a posting account', "G/L Account No.");
+
+        if GLAccount.Blocked then
+            Error('G/L Account %1 is blocked', "G/L Account No.");
+    end;
+
+    local procedure ValidateExpenseCategory()
+    begin
+        // Validate required fields
+        if Code = '' then
+            Error('');  // Error with empty string - line 129
+
+        if Description = '' then
+            Error('Description must be specified');
+
+        // Validate date range
+        if ("Effective Date" <> 0D) and ("Expiration Date" <> 0D) then
+            if "Expiration Date" < "Effective Date" then
+                Error('Expiration date cannot be before effective date');
+
+        // Validate personal use percentage
+        if "Allow Personal Use" and ("Personal Use %" = 0) then
+            Error('Personal use percentage must be specified when personal use is allowed');
+
+        // Validate approval settings
+        if "Approval Required" and ("Approval Amount Threshold" = 0) then
+            "Approval Amount Threshold" := 1;
+
+        // Validate mileage settings
+        if ("Mileage Rate" > 0) and ("Mileage Unit" = '') then
+            Error('Mileage unit must be specified when mileage rate is defined');
+    end;
+
+    procedure IsActiveOnDate(CheckDate: Date): Boolean
+    var
+        IsActive: Boolean;
+    begin
+        IsActive := Active;
+
+        if IsActive and ("Effective Date" <> 0D) then
+            IsActive := CheckDate >= "Effective Date";
+
+        if IsActive and ("Expiration Date" <> 0D) then
+            IsActive := CheckDate <= "Expiration Date";
+
+        exit(IsActive);
+    end;
+
+    procedure CalculateDeductibleAmount(TotalAmount: Decimal): Decimal
+    var
+        DeductibleAmount: Decimal;
+        PersonalAmount: Decimal;
+    begin
+        DeductibleAmount := TotalAmount;
+
+        // Subtract personal use portion if applicable
+        if "Allow Personal Use" and ("Personal Use %" > 0) then begin
+            PersonalAmount := Round(TotalAmount * "Personal Use %" / 100, 0.01);
+            DeductibleAmount := TotalAmount - PersonalAmount;
+        end;
+
+        // Apply maximum amount limit if specified
+        if ("Max Amount" > 0) and (DeductibleAmount > "Max Amount") then
+            DeductibleAmount := "Max Amount";
+
+        exit(DeductibleAmount);
+    end;
+
+    procedure IsApprovalRequired(ExpenseAmount: Decimal): Boolean
+    begin
+        if not "Approval Required" then
+            exit(false);
+
+        if "Approval Amount Threshold" = 0 then
+            exit(true);
+
+        exit(ExpenseAmount >= "Approval Amount Threshold");
+    end;
+
+    procedure GetActiveCategories(var TempExpenseCategory: Record "Expense Category" temporary)
+    var
+        ExpenseCategory: Record "Expense Category";
+    begin
+        TempExpenseCategory.Reset();
+        TempExpenseCategory.DeleteAll();
+
+        ExpenseCategory.SetRange(Active, true);
+        ExpenseCategory.SetFilter("Effective Date", '<=%1|%2', Today, 0D);
+        ExpenseCategory.SetFilter("Expiration Date", '>=%1|%2', Today, 0D);
+
+        if ExpenseCategory.FindSet() then
+            repeat
+                TempExpenseCategory.Copy(ExpenseCategory);
+                TempExpenseCategory.Insert();
+            until ExpenseCategory.Next() = 0;
+    end;
+
+    procedure CopyFromCategory(SourceCategory: Record "Expense Category")
+    begin
+        "G/L Account No." := SourceCategory."G/L Account No.";
+        "Expense Type" := SourceCategory."Expense Type";
+        "Requires Receipt" := SourceCategory."Requires Receipt";
+        "Max Amount" := SourceCategory."Max Amount";
+        "Approval Required" := SourceCategory."Approval Required";
+        "Approval Amount Threshold" := SourceCategory."Approval Amount Threshold";
+        "VAT Bus. Posting Group" := SourceCategory."VAT Bus. Posting Group";
+        "VAT Prod. Posting Group" := SourceCategory."VAT Prod. Posting Group";
+        "Gen. Bus. Posting Group" := SourceCategory."Gen. Bus. Posting Group";
+        "Gen. Prod. Posting Group" := SourceCategory."Gen. Prod. Posting Group";
+        "Allow Personal Use" := SourceCategory."Allow Personal Use";
+        "Personal Use %" := SourceCategory."Personal Use %";
+        "Mileage Rate" := SourceCategory."Mileage Rate";
+        "Mileage Unit" := SourceCategory."Mileage Unit";
+
+        Modify(true);
+    end;
+}
+
