+                    if not UploadIntoStream('Select attribute file', '', 'CSV Files|*.csv', FilePath, ImportStream) then
+                        exit;
+
+                    ImportResult := ImportManager.ImportFromCSV(ImportStream);
+                    if ImportResult then
+                        Message('Attributes imported successfully.')
+                    else
+                        Message('Import completed with errors. Please review the results.');
+                end;
+            }
+            action("Validate Attributes")
+            {
+                ApplicationArea = Basic, Suite;
+                Caption = 'Validate Attributes';
+                Image = CheckRulesSyntax;
+                ToolTip = 'Validate all attribute definitions for consistency.';
+
+                trigger OnAction()
+                var
+                    AttributeValidator: Codeunit "Item Attribute Validator";
+                    ValidationResults: Record "Validation Result" temporary;
+                    ValidationPassed: Boolean;
+                begin
+                    ValidationPassed := AttributeValidator.ValidateAllAttributes(ValidationResults);
+
+                    if ValidationPassed then
+                        Message('All attributes are valid.')
+                    else begin
+                        Message('Validation found issues. Please review the results.');
+                        Page.RunModal(Page::"Validation Results", ValidationResults);
+                    end;
+                end;
+            }
+            action("Assign to Items")
+            {
+                ApplicationArea = Basic, Suite;
+                Caption = 'Assign to Items';
+                Image = ItemSubstitution;
+                ToolTip = 'Assign selected attributes to items.';
+
+                trigger OnAction()
+                var
+                    ItemAttributeAssignment: Page "Item Attribute Assignment";
+                    SelectedAttributes: Record "Item Attribute";
+                begin
+                    CurrPage.SetSelectionFilter(SelectedAttributes);
+                    if SelectedAttributes.IsEmpty() then begin
+                        Message('Please select one or more attributes to assign.');
+                        exit;
+                    end;
+
+                    ItemAttributeAssignment.SetSelectedAttributes(SelectedAttributes);
+                    ItemAttributeAssignment.RunModal();
+                end;
+            }
+        }
+        area(reporting)
+        {
+            action("Attribute Usage Report")
+            {
+                ApplicationArea = Basic, Suite;
+                Caption = 'Attribute Usage Report';
+                Image = "Report";
+                RunObject = Report "Item Attribute Usage";
+                ToolTip = 'View a report showing how attributes are used across items.';
+            }
+        }
+    }
+
+    trigger OnOpenPage()
+    var
+        FeatureManagement: Codeunit "Feature Management";
+        NotificationManager: Codeunit "Notification Manager";
+        BlankOptionAttributeNotification: Notification;
+    begin
+        if not FeatureManagement.IsEnabled('ItemAttributes') then begin
+            Message('Item attributes feature is not enabled. Please contact your system administrator.');
+            CurrPage.Close();
+        end;
+
+        // Check for blank option attributes and show notification
+        if HasBlankOptionAttributes() then begin
+            BlankOptionAttributeNotification.Id := CreateGuid();
+            BlankOptionAttributeNotification.Message := 'Some option attributes have blank values that may cause issues.';
+            BlankOptionAttributeNotification.Scope := NotificationScope::LocalScope;
+            BlankOptionAttributeNotification.AddAction('Review Attributes', Codeunit::"Item Attribute Management", 'ReviewBlankOptions');
+            BlankOptionAttributeNotification.Send();  // Using Msg suffix for notification - line 165
+        end;
+    end;
+
+    trigger OnAfterGetRecord()
+    begin
+        // Update attribute statistics
+        UpdateAttributeStatistics();
+    end;
+
+    trigger OnNewRecord(BelowxRec: Boolean)
+    begin
+        Rec.Type := Rec.Type::Text;
+        Rec.Blocked := false;
+    end;
+
+    local procedure HasBlankOptionAttributes(): Boolean
+    var
+        ItemAttribute: Record "Item Attribute";
+        ItemAttributeValue: Record "Item Attribute Value";
+        HasBlankValues: Boolean;
+    begin
+        HasBlankValues := false;
+
+        ItemAttribute.SetRange(Type, ItemAttribute.Type::Option);
+        if ItemAttribute.FindSet() then
+            repeat
+                ItemAttributeValue.SetRange("Attribute ID", ItemAttribute.ID);
+                ItemAttributeValue.SetRange(Value, '');
+                if not ItemAttributeValue.IsEmpty() then begin
+                    HasBlankValues := true;
+                    break;
+                end;
+            until ItemAttribute.Next() = 0;
+
+        exit(HasBlankValues);
+    end;
+
+    local procedure UpdateAttributeStatistics()
+    var
+        ItemAttributeValueMapping: Record "Item Attribute Value Mapping";
+        UsageCount: Integer;
+    begin
+        // Count how many items use this attribute
+        ItemAttributeValueMapping.SetRange("Item Attribute ID", Rec.ID);
+        UsageCount := ItemAttributeValueMapping.Count();
+
+        // Update the usage count field (would need to add this field to the table)
+        // Rec."Usage Count" := UsageCount;
+        // Rec.Modify();
+    end;
+
+    procedure SetItemCategoryFilter(ItemCategoryCode: Code[20])
+    var
+        ItemCategoryItemAttribute: Record "Item Category - Item Attribute";
+        AttributeFilter: Text;
+        AttributeId: Integer;
+    begin
+        ItemCategoryItemAttribute.SetRange("Item Category Code", ItemCategoryCode);
+
+        if ItemCategoryItemAttribute.FindSet() then begin
+            repeat
+                AttributeId := ItemCategoryItemAttribute."Item Attribute ID";
+                if AttributeFilter <> '' then
+                    AttributeFilter := AttributeFilter + '|';
+                AttributeFilter := AttributeFilter + Format(AttributeId);
+            until ItemCategoryItemAttribute.Next() = 0;
+
+            Rec.SetFilter(ID, AttributeFilter);
+        end else
+            Rec.SetRange(ID, -1); // Show no records if category has no attributes
+    end;
+
+    procedure CreateDefaultAttributes()
+    var
+        ItemAttribute: Record "Item Attribute";
+        DefaultAttributes: List of [Text];
+        DefaultTypes: List of [Option];
+        AttributeName: Text;
+        i: Integer;
+    begin
+        // Define default attributes
+        DefaultAttributes.Add('Color');
+        DefaultAttributes.Add('Size');
+        DefaultAttributes.Add('Material');
+        DefaultAttributes.Add('Weight');
+        DefaultAttributes.Add('Dimensions');
+
+        for i := 1 to DefaultAttributes.Count() do begin
+            AttributeName := DefaultAttributes.Get(i);
+            if not AttributeExists(AttributeName) then begin
+                ItemAttribute.Init();
+                ItemAttribute.Name := CopyStr(AttributeName, 1, MaxStrLen(ItemAttribute.Name));
+
+                case i of
+                    1, 2, 3:
+                        ItemAttribute.Type := ItemAttribute.Type::Option;
+                    4:
+                        begin
+                            ItemAttribute.Type := ItemAttribute.Type::Decimal;
+                            ItemAttribute."Unit of Measure" := 'KG';
+                        end;
+                    5:
+                        ItemAttribute.Type := ItemAttribute.Type::Text;
+                end;
+
+                ItemAttribute.Insert(true);
+            end;
+        end;
+
+        Message('%1 default attributes created.', DefaultAttributes.Count());
+    end;
+
+    local procedure AttributeExists(AttributeName: Text): Boolean
+    var
+        ItemAttribute: Record "Item Attribute";
+    begin
+        ItemAttribute.SetRange(Name, AttributeName);
+        exit(not ItemAttribute.IsEmpty());
+    end;
+
+    var
+        ImportStream: InStream;
+        BlankOptionAttributeNotificationMsg: Label 'Some option attributes have blank values that may cause issues.';
+}
+
diff --git a/src/SCMSupplyPlanningIV.Codeunit.al b/src/SCMSupplyPlanningIV.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/SCMSupplyPlanningIV.Codeunit.al
@@ -0,0 +1,105 @@
+codeunit 50116 "SCM Supply Planning IV"
+{
+    Subtype = Test;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+
+        AssemblyOrderCreatedMsg: Label 'Assembly order %1 has been created successfully.', Comment = '%1 = Order No.';
+
+    [Test]
+    procedure TestCreateAssemblyOrder()
+    var
+        Item: Record Item;
+        AssemblyHeader: Record "Assembly Header";
+        OrderNo: Code[20];
+    begin
+        // Setup
+        LibraryInventory.CreateItem(Item);
+        Item."Assembly Policy" := Item."Assembly Policy"::"Assemble-to-Order";
+        Item.Modify(true);
+
+        // Exercise
+        OrderNo := CreateAssemblyOrderForItem(Item."No.", 10);
+
+        // Verify
+        AssemblyHeader.Get(AssemblyHeader."Document Type"::Order, OrderNo);
+        Assert.AreEqual(Item."No.", AssemblyHeader."Item No.", 'Item number should match');
+        Assert.AreEqual(10, AssemblyHeader.Quantity, AssemblyOrderCreatedMsg);  // Wrong suffix usage - line 58
+    end;
+
+    [Test]
+    procedure TestAssemblyOrderQuantityValidation()
+    var
+        Item: Record Item;
+        AssemblyHeader: Record "Assembly Header";
+        OrderNo: Code[20];
+        ExpectedQuantity: Decimal;
+    begin
+        // Setup
+        LibraryInventory.CreateItem(Item);
+        ExpectedQuantity := 25;
+
+        // Exercise
+        OrderNo := CreateAssemblyOrderForItem(Item."No.", ExpectedQuantity);
+
+        // Verify
+        AssemblyHeader.Get(AssemblyHeader."Document Type"::Order, OrderNo);
+        Assert.AreEqual(ExpectedQuantity, AssemblyHeader.Quantity,
+            'Assembly order quantity should match expected value');
+    end;
+
+    [Test]
+    procedure TestMultipleAssemblyOrders()
+    var
+        Item: Record Item;
+        AssemblyHeader: Record "Assembly Header";
+        OrderCount: Integer;
+        i: Integer;
+        OrderNo: Code[20];
+    begin
+        // Setup
+        LibraryInventory.CreateItem(Item);
+        OrderCount := 5;
+
+        // Exercise
+        for i := 1 to OrderCount do begin
+            OrderNo := CreateAssemblyOrderForItem(Item."No.", 10 * i);
+
+            // Verify each order
+            AssemblyHeader.Get(AssemblyHeader."Document Type"::Order, OrderNo);
+            Assert.AreEqual(Item."No.", AssemblyHeader."Item No.", 'Item should match for order ' + Format(i));
+        end;
+
+        // Verify total count
+        AssemblyHeader.SetRange("Item No.", Item."No.");
+        Assert.AreEqual(OrderCount, AssemblyHeader.Count(), 'Should have created expected number of orders');
+    end;
+
+    local procedure CreateAssemblyOrderForItem(ItemNo: Code[20]; Quantity: Decimal): Code[20]
+    var
+        AssemblyHeader: Record "Assembly Header";
+        NoSeriesManagement: Codeunit NoSeriesManagement;
+    begin
+        AssemblyHeader.Init();
+        AssemblyHeader."Document Type" := AssemblyHeader."Document Type"::Order;
+        AssemblyHeader."No." := NoSeriesManagement.GetNextNo(GetAssemblyOrderNos(), Today, true);
+        AssemblyHeader."Item No." := ItemNo;
+        AssemblyHeader.Quantity := Quantity;
+        AssemblyHeader."Due Date" := CalcDate('<+7D>', Today);
+        AssemblyHeader.Insert(true);
+
+        exit(AssemblyHeader."No.");
+    end;
+
+    local procedure GetAssemblyOrderNos(): Code[20]
+    var
+        AssemblySetup: Record "Assembly Setup";
+    begin
+        AssemblySetup.Get();
+        exit(AssemblySetup."Assembly Order Nos.");
+    end;
+}
+

diff --git a/src/ReportFormatting.Codeunit.al b/src/ReportFormatting.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/ReportFormatting.Codeunit.al
@@ -0,0 +1,29 @@
+codeunit 50302 "Report Formatting"
+{
+    local procedure RunBatchProcess()
+    var
+        Customer: Record Customer;
+        ProcessedCount: Integer;
+    begin
+        Customer.SetLoadFields("No.", Blocked);
+        if not Customer.FindSet() then
+            Error('No customers found for processing.');
+
+        repeat
+            ProcessedCount += 1;
+            if Customer.Blocked <> Customer.Blocked::" " then
+                Error('Customer %1 is blocked and cannot be processed.', Customer."No.");
+        until Customer.Next() = 0;
+
+        if Confirm('Do you want to see the processing summary?') then
+            Message('Successfully processed %1 customers.', ProcessedCount);
+    end;
+
+    local procedure ValidateSetup()
+    var
+        ServiceSetup: Record "Service Mgt. Setup";
+    begin
+        if not ServiceSetup.Get() then
+            Error('Service Management Setup has not been configured.');
+    end;
+}

