+codeunit 50102 ModernAPIHelper
+{
+    [Obsolete('Use GetCustomerDataV2() instead', '25.0')]
+    procedure GetCustomerData(CustomerNo: Code[20]): Text
+    begin
+        // This LOOKS like problematic obsolete usage because we're calling
+        // an obsolete procedure, but it's actually CORRECT because:
+        // 1. This procedure itself is marked as obsolete (being phased out)  
+        // 2. It provides backward compatibility during transition period
+        // 3. The obsolete call is encapsulated within another obsolete method
+        // 4. This is the documented migration pattern for gradual deprecation
+
+        exit(GetLegacyCustomerInfo(CustomerNo));
+    end;
+
+    procedure GetCustomerDataV2(CustomerNo: Code[20]): JsonObject
+    var
+        Customer: Record Customer;
+        JsonResult: JsonObject;
+    begin
+        // This is the NEW version that replaces the obsolete method above
+        // It uses modern JsonObject instead of plain text
+        if Customer.Get(CustomerNo) then begin
+            JsonResult.Add('CustomerNo', Customer."No.");
+            JsonResult.Add('Name', Customer.Name);
+            JsonResult.Add('CreditLimit', Customer."Credit Limit (LCY)");
+            JsonResult.Add('Balance', Customer."Balance (LCY)");
+        end;
+        exit(JsonResult);
+    end;
+
+    [Obsolete('Internal helper method, use GetCustomerDataV2() instead', '25.0')]
+    local procedure GetLegacyCustomerInfo(CustomerNo: Code[20]): Text
+    var
+        Customer: Record Customer;
+    begin
+        // This obsolete method is CORRECTLY used by the obsolete public method
+        // during the transition period. This is NOT a violation because:
+        // 1. Both calling and called methods are marked obsolete together
+        // 2. This maintains functionality while guiding users to new API
+        // 3. Internal obsolete-to-obsolete calls are part of migration strategy
+
+        if Customer.Get(CustomerNo) then
+            exit(StrSubstNo('%1|%2|%3', Customer."No.", Customer.Name, Customer."Credit Limit (LCY)"));
+        exit('');
+    end;
+}

