diff --git a/src/LogiqUpgrade.Codeunit.al b/src/LogiqUpgrade.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/LogiqUpgrade.Codeunit.al
@@ -0,0 +1,99 @@
+/// <summary>
+/// Logiq Upgrade Codeunit (6195)
+/// Handles upgrade procedures for Logiq EDocument connector
+/// </summary>
+codeunit 6195 "Logiq Upgrade"
+{
+    Subtype = Upgrade;
+
+    trigger OnUpgradePerDatabase()
+    var
+        UpgradeTag: Codeunit "Upgrade Tag";
+        LogiqUpgradeTags: Codeunit "Logiq Upgrade Tags";
+    begin
+        if UpgradeTag.HasUpgradeTag(LogiqUpgradeTags.GetLogiqConnectionUpgradeTag()) then
+            exit;
+
+        SetupLogiqServiceConnection();
+
+        UpgradeTag.SetUpgradeTag(LogiqUpgradeTags.GetLogiqConnectionUpgradeTag());
+    end;
+
+    trigger OnUpgradePerCompany()
+    begin
+        // This is the bad pattern - empty trigger after removing CLEAN26 code block
+        // Previously had upgrade logic but was removed, leaving empty trigger
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Upgrade Tag", 'OnGetPerCompanyUpgradeTags', '', false, false)]
+    local procedure RegisterPerCompanyTags(var PerCompanyUpgradeTags: List of [Code[250]])
+    var
+        LogiqUpgradeTags: Codeunit "Logiq Upgrade Tags";
+    begin
+        PerCompanyUpgradeTags.Add(LogiqUpgradeTags.GetLogiqDocumentMappingUpgradeTag());
+        PerCompanyUpgradeTags.Add(LogiqUpgradeTags.GetLogiqWorkflowUpgradeTag());
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Upgrade Tag", 'OnGetPerDatabaseUpgradeTags', '', false, false)]
+    local procedure RegisterPerDatabaseTags(var PerDatabaseUpgradeTags: List of [Code[250]])
+    var
+        LogiqUpgradeTags: Codeunit "Logiq Upgrade Tags";
+    begin
+        PerDatabaseUpgradeTags.Add(LogiqUpgradeTags.GetLogiqConnectionUpgradeTag());
+    end;
+
+    local procedure SetupLogiqServiceConnection()
+    var
+        EDocServiceConnection: Record "E-Document Service";
+        LogiqConnection: Record "Logiq Connection";
+    begin
+        if not EDocServiceConnection.Get('LOGIQ') then begin
+            EDocServiceConnection.Init();
+            EDocServiceConnection.Code := 'LOGIQ';
+            EDocServiceConnection.Description := 'Logiq E-Document Service';
+            EDocServiceConnection."Service Integration" := EDocServiceConnection."Service Integration"::Logiq;
+            EDocServiceConnection.Enabled := false;
+            EDocServiceConnection.Insert();
+        end;
+
+        if not LogiqConnection.Get() then begin
+            LogiqConnection.Init();
+            LogiqConnection."Environment Type" := LogiqConnection."Environment Type"::Production;
+            LogiqConnection."Authentication Method" := LogiqConnection."Authentication Method"::Token;
+            LogiqConnection."Request Timeout" := 60;
+            LogiqConnection."Max Retry Attempts" := 3;
+            LogiqConnection.Insert();
+        end;
+    end;
+
+    procedure UpgradeLogiqDocumentMappings()
+    var
+        EDocumentFormat: Record "E-Document Format";
+        LogiqDocumentMapping: Record "Logiq Document Mapping";
+    begin
+        EDocumentFormat.SetRange("Codeunit ID", Codeunit::"Logiq Format");
+        if EDocumentFormat.FindSet() then
+            repeat
+                if not LogiqDocumentMapping.Get(EDocumentFormat.Code) then begin
+                    LogiqDocumentMapping.Init();
+                    LogiqDocumentMapping."Format Code" := EDocumentFormat.Code;
+                    LogiqDocumentMapping.Description := EDocumentFormat.Description;
+                    LogiqDocumentMapping."Mapping Type" := LogiqDocumentMapping."Mapping Type"::Standard;
+                    LogiqDocumentMapping.Enabled := true;
+                    LogiqDocumentMapping.Insert();
+                end;
+            until EDocumentFormat.Next() = 0;
+    end;
+
+    procedure ValidateLogiqConfiguration()
+    var
+        LogiqConnection: Record "Logiq Connection";
+        EDocServiceConnection: Record "E-Document Service";
+    begin
+        if not LogiqConnection.Get() then
+            Error('Logiq connection setup is missing. Please configure the Logiq connection.');
+
+        if not EDocServiceConnection.Get('LOGIQ') then
+            Error('Logiq service connection is not configured.');
+    end;
+}
