diff --git a/src/Upgrade.Codeunit.al b/src/Upgrade.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/Upgrade.Codeunit.al
@@ -0,0 +1,88 @@
+/// <summary>
+/// EDocument Pagero Upgrade Codeunit (6171)
+/// Handles upgrade procedures for Pagero connector
+/// </summary>
+codeunit 6171 "Upgrade"
+{
+    Subtype = Upgrade;
+
+    trigger OnUpgradePerDatabase()
+    var
+        UpgradeTag: Codeunit "Upgrade Tag";
+        PageroUpgradeTags: Codeunit "Pagero Upgrade Tags";
+    begin
+        if UpgradeTag.HasUpgradeTag(PageroUpgradeTags.GetPageroConnectionSetupUpgradeTag()) then
+            exit;
+
+        // Setup default connection parameters
+        SetupDefaultPageroConnection();
+
+        UpgradeTag.SetUpgradeTag(PageroUpgradeTags.GetPageroConnectionSetupUpgradeTag());
+    end;
+
+    trigger OnUpgradePerCompany()
+    begin
+        // This is the bad pattern - empty trigger body after code removal
+        // Previously contained upgrade logic but now empty
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Upgrade Tag", 'OnGetPerCompanyUpgradeTags', '', false, false)]
+    local procedure RegisterPerCompanyTags(var PerCompanyUpgradeTags: List of [Code[250]])
+    var
+        PageroUpgradeTags: Codeunit "Pagero Upgrade Tags";
+    begin
+        PerCompanyUpgradeTags.Add(PageroUpgradeTags.GetPageroDocumentLayoutUpgradeTag());
+        PerCompanyUpgradeTags.Add(PageroUpgradeTags.GetPageroServiceConnectionUpgradeTag());
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Upgrade Tag", 'OnGetPerDatabaseUpgradeTags', '', false, false)]
+    local procedure RegisterPerDatabaseTags(var PerDatabaseUpgradeTags: List of [Code[250]])
+    var
+        PageroUpgradeTags: Codeunit "Pagero Upgrade Tags";
+    begin
+        PerDatabaseUpgradeTags.Add(PageroUpgradeTags.GetPageroConnectionSetupUpgradeTag());
+    end;
+
+    local procedure SetupDefaultPageroConnection()
+    var
+        EDocServiceConnection: Record "E-Document Service";
+        PageroConnection: Record "Pagero Connection";
+    begin
+        if not EDocServiceConnection.Get('PAGERO') then begin
+            EDocServiceConnection.Init();
+            EDocServiceConnection.Code := 'PAGERO';
+            EDocServiceConnection.Description := 'Pagero E-Document Service';
+            EDocServiceConnection."Service Integration" := EDocServiceConnection."Service Integration"::Pagero;
+            EDocServiceConnection.Enabled := false;
+            EDocServiceConnection.Insert();
+        end;
+
+        if not PageroConnection.Get() then begin
+            PageroConnection.Init();
+            PageroConnection."Environment Type" := PageroConnection."Environment Type"::Sandbox;
+            PageroConnection."Authentication Type" := PageroConnection."Authentication Type"::"Client Credentials";
+            PageroConnection."Timeout (seconds)" := 30;
+            PageroConnection.Insert();
+        end;
+    end;
+
+    procedure UpgradePageroDocumentLayouts()
+    var
+        EDocumentServiceStatus: Record "E-Document Service Status";
+        PageroDocumentLayout: Record "Pagero Document Layout";
+    begin
+        // Upgrade document layout mappings for new Pagero formats
+        EDocumentServiceStatus.SetRange("E-Document Service Code", 'PAGERO');
+        if EDocumentServiceStatus.FindSet() then
+            repeat
+                if not PageroDocumentLayout.Get(EDocumentServiceStatus."Document Type", 'PEPPOL_BIS3') then begin
+                    PageroDocumentLayout.Init();
+                    PageroDocumentLayout."Document Type" := EDocumentServiceStatus."Document Type";
+                    PageroDocumentLayout."Layout Code" := 'PEPPOL_BIS3';
+                    PageroDocumentLayout.Description := 'PEPPOL BIS3 Format';
+                    PageroDocumentLayout.Enabled := true;
+                    PageroDocumentLayout.Insert();
+                end;
+            until EDocumentServiceStatus.Next() = 0;
+    end;
+}
