+            ObsoleteState = Pending;
+            ObsoleteReason = 'Use Buy-from Vendor No. field instead';
+            ObsoleteTag = '26.0';
+        }
+    }
+
+    procedure UpdateWHTAmounts()
+    var
+        PurchCrMemoLine: Record "Purch. Cr. Memo Line";
+        TotalWHTAmount: Decimal;
+        TotalWHTAmountLCY: Decimal;
+    begin
+        PurchCrMemoLine.SetRange("Document No.", "No.");
+        PurchCrMemoLine.SetFilter("WHT Amount", '<>0');
+        if PurchCrMemoLine.FindSet() then
+            repeat
+                TotalWHTAmount += PurchCrMemoLine."WHT Amount";
+                TotalWHTAmountLCY += PurchCrMemoLine."WHT Amount (LCY)";
+            until PurchCrMemoLine.Next() = 0;
+
+        "Total WHT Amount" := TotalWHTAmount;
+        "Total WHT Amount (LCY)" := TotalWHTAmountLCY;
+        Modify();
+    end;
+
+    procedure SettleWHT()
+    var
+        WHTEntry: Record "WHT Entry";
+        WHTSettlement: Codeunit "WHT Settlement";
+    begin
+        WHTEntry.SetCurrentKey("Document Type", "Document No.");
+        WHTEntry.SetRange("Document Type", WHTEntry."Document Type"::"Credit Memo");
+        WHTEntry.SetRange("Document No.", "No.");
+        WHTEntry.SetRange(Settled, false);
+
+        if WHTEntry.FindSet() then begin
+            WHTSettlement.SettleWHT(WHTEntry);
+            "WHT Settled" := true;
+            "WHT Settlement Date" := WorkDate();
+            Modify();
+        end;
+    end;
+
+    procedure ValidateWHTSetup()
+    var
+        WHTPostingSetup: Record "WHT Posting Setup";
+    begin
+        if "WHT Business Posting Group" <> '' then begin
+            TestField("WHT Product Posting Group");
+            if not WHTPostingSetup.Get("WHT Business Posting Group", "WHT Product Posting Group") then
+                Error('WHT Posting Setup does not exist for %1, %2', "WHT Business Posting Group", "WHT Product Posting Group");
+        end;
+    end;
+
+    procedure GetWHTCertificateAmount(): Decimal
+    var
+        WHTCertificate: Record "WHT Certificate";
+    begin
+        if "WHT Certificate No." = '' then
+            exit(0);
+
+        if WHTCertificate.Get("WHT Certificate No.") then
+            exit(WHTCertificate."WHT Amount");
+
+        exit(0);
+    end;
+}
