+        "Modified By" := UserId;
+        "Modified DateTime" := CurrentDateTime;
+    end;
+
+    trigger OnDelete()
+    var
+        ContactSyncEntry: Record "Contact Sync Entry";
+    begin
+        ContactSyncEntry.SetRange("Folder ID", "Folder ID");
+        ContactSyncEntry.DeleteAll();
+    end;
+
+    procedure SyncContacts()
+    var
+        ContactSyncMgt: Codeunit "Contact Sync. Management";
+    begin
+        TestField("Sync Enabled", true);
+        TestField(Blocked, false);
+
+        ContactSyncMgt.SyncFolder(Rec);
+    end;
+
+    procedure ScheduleNextSync()
+    begin
+        if "Auto Sync Interval" > 0 then
+            "Next Sync DateTime" := CurrentDateTime + "Auto Sync Interval";
+    end;
+
+    procedure UpdateSyncStatistics()
+    var
+        ContactSyncEntry: Record "Contact Sync Entry";
+    begin
+        ContactSyncEntry.SetRange("Folder ID", "Folder ID");
+        "Total Items" := ContactSyncEntry.Count();
+
+        ContactSyncEntry.SetRange("Sync Status", ContactSyncEntry."Sync Status"::Synced);
+        "Synced Items" := ContactSyncEntry.Count();
+
+        "Last Sync DateTime" := CurrentDateTime;
+        Modify();
+    end;
+
+    procedure GetChildFolders(var ChildFolders: Record "Contact Sync Folder")
+    begin
+        ChildFolders.SetRange("Parent Id", "Folder ID");
+        ChildFolders.SetRange("Sync Enabled", true);
+        ChildFolders.SetRange(Blocked, false);
+    end;
+
+    procedure HasPendingSync(): Boolean
+    begin
+        CalcFields("Pending Items");
+        exit("Pending Items" > 0);
+    end;
+
+    procedure ValidateSyncConfiguration()
+    var
+        ExchangeServiceConnection: Record "Exchange Service Connection";
+    begin
+        TestField("Exchange Service");
+
+        if not ExchangeServiceConnection.Get("Exchange Service") then
+            Error('Exchange Service Connection %1 does not exist.', "Exchange Service");
+
+        ExchangeServiceConnection.TestField(Enabled, true);
+    end;
+}
