+    end;
+
+    trigger OnDelete()
+    var
+        BankAccount: Record "Bank Account";
+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        VendLedgerEntry: Record "Vendor Ledger Entry";
+    begin
+        BankAccount.SetRange("Currency Code", Code);
+        if not BankAccount.IsEmpty then
+            Error('Cannot delete currency %1 because it is used by bank accounts.', Code);
+
+        CustLedgerEntry.SetRange("Currency Code", Code);
+        if not CustLedgerEntry.IsEmpty then
+            Error('Cannot delete currency %1 because it is used in customer ledger entries.', Code);
+
+        VendLedgerEntry.SetRange("Currency Code", Code);
+        if not VendLedgerEntry.IsEmpty then
+            Error('Cannot delete currency %1 because it is used in vendor ledger entries.', Code);
+    end;
+
+    local procedure SetDefaultValues()
+    begin
+        if "Exchange Rate Amount" = 0 then
+            "Exchange Rate Amount" := 1;
+
+        if "Relational Exch. Rate Amount" = 0 then
+            "Relational Exch. Rate Amount" := 1;
+
+        if "Amount Rounding Precision" = 0 then
+            "Amount Rounding Precision" := 0.01;
+
+        if "Unit-Amount Rounding Precision" = 0 then
+            "Unit-Amount Rounding Precision" := 0.00001;
+
+        if "Invoice Rounding Precision" = 0 then
+            "Invoice Rounding Precision" := 1;
+
+        if "Appln. Rounding Precision" = 0 then
+            "Appln. Rounding Precision" := 0.01;
+    end;
+
+    procedure InitRoundingPrecision()
+    begin
+        "Amount Rounding Precision" := 0.01;
+        "Unit-Amount Rounding Precision" := 0.00001;
+        "Appln. Rounding Precision" := 0.01;
+        "Invoice Rounding Precision" := 1;
+        "Invoice Rounding Type" := "Invoice Rounding Type"::Nearest;
+        "VAT Rounding Type" := "VAT Rounding Type"::Nearest;
+    end;
+
+    procedure GetCurrencySymbol(): Text[10]
+    begin
+        if Symbol <> '' then
+            exit(Symbol);
+
+        exit(Code);
+    end;
+}
