+        "Archive Retention Days" := 365;
+    end;
+
+    procedure ValidateAIServiceSetup()
+    begin
+        if "Enable AI Processing" then begin
+            TestField("AI Service URL");
+            TestField("AI Service Key");
+        end;
+
+        if "Enable OCR Processing" then begin
+            TestField("OCR Service URL");
+            TestField("OCR Service Key");
+        end;
+
+        if "Use MLLM Processing" then begin
+            TestField("MLLM Service Endpoint");
+            TestField("MLLM API Key");
+            TestField("MLLM Model Name");
+        end;
+    end;
+
+    procedure ValidatePostingSetup()
+    var
+        GenBusPostingGroup: Record "Gen. Business Posting Group";
+        GenProdPostingGroup: Record "Gen. Product Posting Group";
+        VATBusPostingGroup: Record "VAT Business Posting Group";
+        VATProdPostingGroup: Record "VAT Product Posting Group";
+    begin
+        if "Default Gen. Bus. Posting Group" <> '' then
+            GenBusPostingGroup.Get("Default Gen. Bus. Posting Group");
+
+        if "Default Gen. Prod. Posting Group" <> '' then
+            GenProdPostingGroup.Get("Default Gen. Prod. Posting Group");
+
+        if "Default VAT Bus. Posting Group" <> '' then
+            VATBusPostingGroup.Get("Default VAT Bus. Posting Group");
+
+        if "Default VAT Prod. Posting Group" <> '' then
+            VATProdPostingGroup.Get("Default VAT Prod. Posting Group");
+    end;
+
+    procedure GetMLLMSettings(var ModelName: Text[100]; var ServiceEndpoint: Text[250]; var Temperature: Decimal): Boolean
+    begin
+        if not "Use MLLM Processing" then
+            exit(false);
+
+        ModelName := "MLLM Model Name";
+        ServiceEndpoint := "MLLM Service Endpoint";
+        Temperature := "MLLM Temperature";
+        exit(true);
+    end;
+}
diff --git a/src/StandardAccount.Table.al b/src/StandardAccount.Table.al
new file mode 100644
--- /dev/null
+++ b/src/StandardAccount.Table.al
@@ -0,0 +1,220 @@
+/// <summary>
+/// Standard Account Table (12330)
+/// Maps standard accounting codes to local G/L accounts
+/// </summary>
+table 12330 "Standard Account"
+{
+    Caption = 'Standard Account';
+    DataClassification = CustomerContent;
+    LookupPageID = "Standard Account List";
+    DrillDownPageID = "Standard Account List";
+
+    fields
+    {
+        field(1; "No."; Code[20])
+        {
+            Caption = 'No.';
+            NotBlank = true;
+        }
+
+        field(2; Description; Text[100])
+        {
+            Caption = 'Description';
+        }
+
+        field(3; "G/L Account No."; Code[20])
+        {
+            Caption = 'G/L Account No.';
+            TableRelation = "G/L Account" WHERE("Account Type" = CONST(Posting), Blocked = CONST(false));
+        }
+
+        field(4; "Type"; Option)
+        {
+            Caption = 'Type';
+            OptionCaption = 'Assets,Liabilities,Equity,Revenue,Expense';
+            OptionMembers = Assets,Liabilities,Equity,Revenue,Expense;
+        }
+
+        field(5; "Extended No."; Code[30]) // This is the bad pattern - new field without upgrade code
+        {
+            Caption = 'Extended No.';
+        }
+
+        field(10; "Country/Region Code"; Code[10])
+        {
+            Caption = 'Country/Region Code';
+            TableRelation = "Country/Region";
+        }
+
+        field(11; "Standard Account Category"; Code[20])
+        {
+            Caption = 'Standard Account Category';
+            TableRelation = "Standard Account Category";
+        }
+
+        field(12; "SAF-T Account Code"; Code[20])
+        {
+            Caption = 'SAF-T Account Code';
+        }
+
+        field(13; "SAF-T Account Type"; Option)
+        {
+            Caption = 'SAF-T Account Type';
+            OptionCaption = 'General Ledger,Accounts Receivable,Accounts Payable,Fixed Assets,Inventory,Other Assets,Equity,Revenue,Expense,Other';
+            OptionMembers = "General Ledger","Accounts Receivable","Accounts Payable","Fixed Assets",Inventory,"Other Assets",Equity,Revenue,Expense,Other;
+        }
+
+        field(14; "Income Statement"; Boolean)
+        {
+            Caption = 'Income Statement';
+        }
+
+        field(15; "Balance Sheet"; Boolean)
+        {
+            Caption = 'Balance Sheet';
+        }
+
+        field(16; "Cash Flow Statement"; Boolean)
+        {
+            Caption = 'Cash Flow Statement';
+        }
+
+        field(17; "Grouping Code"; Code[20])
+        {
+            Caption = 'Grouping Code';
+            TableRelation = "Standard Account Grouping";
+        }
+
+        field(18; "Sort Order"; Integer)
+        {
+            Caption = 'Sort Order';
+        }
+
+        field(19; "Last Date Modified"; Date)
+        {
+            Caption = 'Last Date Modified';
+            Editable = false;
+        }
+
+        field(20; Blocked; Boolean)
+        {
+            Caption = 'Blocked';
+        }
+    }
+
+    keys
+    {
+        key(Key1; "No.")
+        {
+            Clustered = true;
+        }
+
+        key(Key2; "Country/Region Code", "Standard Account Category")
+        {
+        }
+
+        key(Key3; "Type", "Sort Order")
+        {
+        }
+
+        key(Key4; "SAF-T Account Type", "SAF-T Account Code")
+        {
+        }
+
+        key(Key5; "Extended No.")
+        {
+        }
+    }
+
+    fieldgroups
+    {
+        fieldgroup(DropDown; "No.", Description, "G/L Account No.", "Type")
+        {
+        }
+
+        fieldgroup(Brick; "No.", Description, "Standard Account Category", Blocked)
+        {
+        }
+    }
+
+    trigger OnInsert()
+    begin
+        "Last Date Modified" := Today;
+    end;
+
+    trigger OnModify()
+    begin
+        "Last Date Modified" := Today;
+    end;
+
+    trigger OnDelete()
+    var
+        StandardAccountMapping: Record "Standard Account Mapping";
+    begin
+        StandardAccountMapping.SetRange("Standard Account No.", "No.");
+        StandardAccountMapping.DeleteAll();
+    end;
+
+    procedure ValidateGLAccountMapping()
+    var
+        GLAccount: Record "G/L Account";
+    begin
+        if "G/L Account No." <> '' then begin
+            GLAccount.Get("G/L Account No.");
+            GLAccount.TestField("Account Type", GLAccount."Account Type"::Posting);
+            GLAccount.TestField(Blocked, false);
+        end;
+    end;
+
+    procedure GetStatementAssignment(): Text
+    var
+        StatementText: Text;
+    begin
+        if "Income Statement" then
+            StatementText += 'Income Statement ';
+
+        if "Balance Sheet" then
+            StatementText += 'Balance Sheet ';
+
+        if "Cash Flow Statement" then
+            StatementText += 'Cash Flow Statement ';
+
+        exit(StatementText.TrimEnd(' '));
+    end;
+
+    procedure SetStatementFlags(AccountType: Option)
+    begin
+        case AccountType of
+            Type::Assets, Type::Liabilities, Type::Equity:
+                begin
+                    "Balance Sheet" := true;
+                    "Income Statement" := false;
+                end;
+            Type::Revenue, Type::Expense:
+                begin
+                    "Income Statement" := true;
+                    "Balance Sheet" := false;
+                end;
+        end;
+    end;
+
+    procedure CreateGLAccountMapping()
+    var
+        GLAccount: Record "G/L Account";
+        StandardAccountMapping: Record "Standard Account Mapping";
+    begin
+        if "G/L Account No." = '' then
+            Error('G/L Account No. must be specified to create mapping.');
+
+        if not GLAccount.Get("G/L Account No.") then
+            Error('G/L Account %1 does not exist.', "G/L Account No.");
+
+        if not StandardAccountMapping.Get("No.", "G/L Account No.") then begin
+            StandardAccountMapping.Init();
+            StandardAccountMapping."Standard Account No." := "No.";
+            StandardAccountMapping."G/L Account No." := "G/L Account No.";
+            StandardAccountMapping."Mapping Type" := StandardAccountMapping."Mapping Type"::Direct;
+            StandardAccountMapping.Insert();
+        end;
+    end;
+}
diff --git a/src/UpgradeExpenseAgentSetup.Codeunit.al b/src/UpgradeExpenseAgentSetup.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/UpgradeExpenseAgentSetup.Codeunit.al
@@ -0,0 +1,120 @@
+/// <summary>
+/// Upgrade Expense Agent Setup Codeunit (69135)
+/// Handles upgrade procedures for Expense Agent setup with direct implementation
+/// </summary>
+codeunit 69135 "Upgrade Expense Agent Setup"
+{
+    Subtype = Upgrade;
+
+    trigger OnUpgradePerDatabase()
+    var
+        InstallExpenseAgentSetup: Codeunit "Install Expense Agent Setup";
+    begin
+        // This is the bad pattern - direct implementation code in trigger instead of method call
+        InstallExpenseAgentSetup.RegisterCapability();
+    end;
+
+    trigger OnUpgradePerCompany()
+    var
+        ExpenseAgentSetup: Record "Expense Agent Setup";
+        UpgradeTag: Codeunit "Upgrade Tag";
+        ExpenseAgentUpgradeTags: Codeunit "Expense Agent Upgrade Tags";
+    begin
+        if UpgradeTag.HasUpgradeTag(ExpenseAgentUpgradeTags.GetExpenseAgentSetupUpgradeTag()) then
+            exit;
+
+        UpgradeExpenseAgentSetup();
+
+        UpgradeTag.SetUpgradeTag(ExpenseAgentUpgradeTags.GetExpenseAgentSetupUpgradeTag());
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Upgrade Tag", 'OnGetPerCompanyUpgradeTags', '', false, false)]
+    local procedure RegisterPerCompanyTags(var PerCompanyUpgradeTags: List of [Code[250]])
+    var
+        ExpenseAgentUpgradeTags: Codeunit "Expense Agent Upgrade Tags";
+    begin
+        PerCompanyUpgradeTags.Add(ExpenseAgentUpgradeTags.GetExpenseAgentSetupUpgradeTag());
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Upgrade Tag", 'OnGetPerDatabaseUpgradeTags', '', false, false)]
+    local procedure RegisterPerDatabaseTags(var PerDatabaseUpgradeTags: List of [Code[250]])
+    var
+        ExpenseAgentUpgradeTags: Codeunit "Expense Agent Upgrade Tags";
+    begin
+        PerDatabaseUpgradeTags.Add(ExpenseAgentUpgradeTags.GetExpenseCapabilityUpgradeTag());
+    end;
+
+    local procedure UpgradeExpenseAgentSetup()
+    var
+        ExpenseAgentSetup: Record "Expense Agent Setup";
+    begin
+        if not ExpenseAgentSetup.Get() then begin
+            ExpenseAgentSetup.Init();
+            ExpenseAgentSetup.Insert();
+        end;
+
+        // Set default values for new fields
+        ExpenseAgentSetup."Enable AI Processing" := true;
+        ExpenseAgentSetup."Max File Size (MB)" := 10;
+        ExpenseAgentSetup."Supported File Types" := 'PDF,JPG,PNG,JPEG';
+        ExpenseAgentSetup."Auto-Submit Threshold" := 100;
+        ExpenseAgentSetup."Receipt Required for Amount" := 50;
+        ExpenseAgentSetup."Mileage Rate per KM" := 0.45;
+        ExpenseAgentSetup."Supervisor Notification Days" := 7;
+        ExpenseAgentSetup."Expense Approval Timeout (Days)" := 14;
+        ExpenseAgentSetup.Modify();
+    end;
+
+    procedure UpgradeExpenseCategories()
+    var
+        ExpenseCategory: Record "Expense Category";
+        GLAccount: Record "G/L Account";
+    begin
+        ExpenseCategory.SetRange("G/L Account No.", '');
+        if ExpenseCategory.FindSet() then
+            repeat
+                // Set default G/L accounts for expense categories without them
+                case ExpenseCategory.Type of
+                    ExpenseCategory.Type::Travel:
+                        if GLAccount.Get('6110') then
+                            ExpenseCategory."G/L Account No." := GLAccount."No.";
+                    ExpenseCategory.Type::Meals:
+                        if GLAccount.Get('6120') then
+                            ExpenseCategory."G/L Account No." := GLAccount."No.";
+                    ExpenseCategory.Type::Accommodation:
+                        if GLAccount.Get('6130') then
+                            ExpenseCategory."G/L Account No." := GLAccount."No.";
+                    ExpenseCategory.Type::Transportation:
+                        if GLAccount.Get('6140') then
+                            ExpenseCategory."G/L Account No." := GLAccount."No.";
+                    ExpenseCategory.Type::Entertainment:
+                        if GLAccount.Get('6150') then
+                            ExpenseCategory."G/L Account No." := GLAccount."No.";
+                end;
+                ExpenseCategory.Modify();
+            until ExpenseCategory.Next() = 0;
+    end;
+
+    procedure UpgradeExpensePaymentMethods()
+    var
+        PaymentMethod: Record "Payment Method";
+        ExpensePaymentMethod: Record "Expense Payment Method";
+    begin
+        // Migrate from Payment Method to Expense Payment Method
+        PaymentMethod.SetRange("Expense Report Type", true);
+        if PaymentMethod.FindSet() then
+            repeat
+                if not ExpensePaymentMethod.Get(PaymentMethod.Code) then begin
+                    ExpensePaymentMethod.Init();
+                    ExpensePaymentMethod.Code := PaymentMethod.Code;
+                    ExpensePaymentMethod.Description := PaymentMethod.Description;
+                    ExpensePaymentMethod."Reimbursable" := not PaymentMethod."Corporate Card";
+                    ExpensePaymentMethod."Corporate Card" := PaymentMethod."Corporate Card";
+                    ExpensePaymentMethod."Requires Receipt" := PaymentMethod."Receipt Required";
+                    ExpensePaymentMethod."Balancing Account Type" := PaymentMethod."Bal. Account Type";
+                    ExpensePaymentMethod."Balancing Account No." := PaymentMethod."Bal. Account No.";
+                    ExpensePaymentMethod.Insert();
+                end;
+            until PaymentMethod.Next() = 0;
+    end;
+}
